import { useState, useEffect } from 'react';
import { MainLayout } from './components/Layout';
import { Toaster } from 'sonner';
import { WorkflowList } from './components/WorkflowManagement';
import { WorkflowBuilder } from './components/WorkflowBuilder';
import { Auth } from './components/Auth';
import { ResetPassword } from './components/ResetPassword';
import { AuthProvider, useAuth } from './hooks/useAuth';
import { Info } from 'lucide-react';
import type { Workflow } from './types';
import { Dashboard } from './components/Dashboard';
import { UserManagement } from './components/UserManagement';
import { StartProcessModal } from './components/StartProcessModal';
import { ProcessExecution } from './components/ProcessExecution';
import { ProcessSearch } from './components/ProcessSearch';
import { Reports } from './components/Reports';
import { OrganizationSettings } from './components/OrganizationSettings';
import { Providers } from './components/Providers';
import { Calendar } from './components/Calendar';
import { OrganizationalChart } from './components/OrganizationalChart';
import { SystemAccounts } from './components/SystemAccounts';
import { IntegrationMonitor } from './components/IntegrationMonitor';

function AppContent() {
  const { user, loading } = useAuth();
  const [activeSection, setActiveSection] = useState('dashboard');
  const [selectedWorkflow, setSelectedWorkflow] = useState<Workflow | null>(null);
  const [shouldOpenForm, setShouldOpenForm] = useState(false);
  const [showStartProcess, setShowStartProcess] = useState(false);
  const [executingProcessId, setExecutingProcessId] = useState<string | null>(null);
  const [dashboardRefreshKey, setDashboardRefreshKey] = useState(0);
  const [isResetPasswordPage, setIsResetPasswordPage] = useState(false);

  // Check if we're on the reset password page
  useEffect(() => {
    const hash = window.location.hash;
    if (hash.includes('type=recovery')) {
      setIsResetPasswordPage(true);
    }
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-100 dark:bg-slate-950">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  // Show reset password page if user clicked on recovery link
  if (isResetPasswordPage) {
    return <ResetPassword />;
  }

  if (!user) {
    return <Auth />;
  }

  // Handle section change from Dashboard
  const handleDashboardAction = (action: string, data?: any) => {
    if (action === 'new-workflow') {
      setActiveSection('workflows');
      setShouldOpenForm(true);
    } else if (action === 'new-process') {
      setShowStartProcess(true);
    } else if (action === 'attend-task') {
      setExecutingProcessId(data);
    } else {
      setActiveSection(action);
    }
  };

  if (selectedWorkflow) {
    return (
      <MainLayout
        activeSection="workflows"
        onSectionChange={(section) => {
          setActiveSection(section);
          setSelectedWorkflow(null);
        }}
      >
        <WorkflowBuilder
          workflow={selectedWorkflow}
          onBack={() => setSelectedWorkflow(null)}
        />
      </MainLayout>
    );
  }

  return (
    <MainLayout
      activeSection={activeSection}
      onSectionChange={(section) => {
        setActiveSection(section);
        setShouldOpenForm(false);
      }}
      onNewProcess={() => setShowStartProcess(true)}
    >
      {activeSection === 'dashboard' && (
        <Dashboard
          onAction={handleDashboardAction}
          refreshTrigger={dashboardRefreshKey}
        />
      )}
      {activeSection === 'workflows' && (
        <WorkflowList
          onSelectWorkflow={setSelectedWorkflow}
          openForm={shouldOpenForm}
          onFormClose={() => setShouldOpenForm(false)}
        />
      )}
      {activeSection === 'users' && <UserManagement />}
      {activeSection === 'organization' && <OrganizationSettings />}
      {activeSection === 'parameters' && <OrganizationSettings onlyParameters />}
      {activeSection === 'settings' && (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[2rem] border border-dashed border-slate-200">
          <div className="p-4 bg-slate-50 rounded-full mb-4">
            <Info className="w-8 h-8 text-slate-400" />
          </div>
          <p className="text-slate-500 font-medium">Configuraci├│n del sistema en desarrollo...</p>
        </div>
      )}
      {activeSection === 'search' && (
        <div className="h-[calc(100vh-9rem)]">
          <ProcessSearch onAttendTask={(id) => setExecutingProcessId(id)} />
        </div>
      )}
      {activeSection === 'providers' && <Providers />}
      {activeSection === 'reports' && <Reports />}
      {activeSection === 'calendar' && <Calendar />}
      {activeSection === 'orgchart' && user?.organization_id && (
        <OrganizationalChart organizationId={user.organization_id} />
      )}
      {activeSection === 'accounts' && <SystemAccounts />}
      {activeSection === 'monitor' && <IntegrationMonitor />}

      {showStartProcess && (
        <StartProcessModal
          onClose={() => setShowStartProcess(false)}
          onStarted={() => {
            setDashboardRefreshKey(prev => prev + 1);
          }}
        />
      )}

      {executingProcessId && (
        <ProcessExecution
          processId={executingProcessId}
          onClose={() => setExecutingProcessId(null)}
          onComplete={() => {
            setDashboardRefreshKey(prev => prev + 1);
          }}
        />
      )}
    </MainLayout>
  );
}

function App() {
  return (
    <AuthProvider>
      <Toaster position="top-right" richColors />
      <AppContent />
    </AuthProvider>
  );
}

export default App;

import { useState, useRef, useEffect } from 'react';
import { Bot, X, Send, Loader2, Sparkles } from 'lucide-react';
import { clsx } from 'clsx';
import { askAICopilot } from '../services/aiService';

interface Message {
    id: string;
    role: 'user' | 'assistant';
    content: string;
}

interface AICopilotProps {
    processContext: any;
    formData: any;
    bimObject?: any;
    bimStates?: Record<number, any>;
}

export function AICopilot({ processContext, formData, bimObject, bimStates }: AICopilotProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<Message[]>([
        { id: '1', role: 'assistant', content: '┬íHola! Soy tu Asistente IA. Puedo ayudarte analizando los datos actuales de esta tarea, recordando pol├¡ticas o dando sugerencias. ┬┐En qu├® te ayudo?' }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const [apiKey] = useState(localStorage.getItem('bpm_openai_key') || '');

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen]);

    // BIMind Auto-open on selection
    useEffect(() => {
        if (bimObject && !isOpen) {
            setIsOpen(true);
            const status = bimStates?.[bimObject.id] || 'pending';
            const statusLabels: Record<string, string> = {
                'pending': 'Pendiente',
                'processing': 'En Proceso',
                'completed': 'Completado',
                'delayed': 'Retrasado'
            };
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'assistant',
                content: `­ƒöì He detectado que seleccionaste: **${bimObject.name}**. Su estado actual es **${statusLabels[status] || status}**. ┬┐Qu├® te gustar├¡a saber sobre este elemento o c├│mo afecta al proceso?`
            }]);
        }
    }, [bimObject]);

    const handleSend = async (messageOverride?: string) => {
        const textToSend = messageOverride || input.trim();
        if (!textToSend || isLoading) return;
        if (!apiKey) {
            setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: 'ÔØî Por favor configura tu API Key de OpenAI en el Arquitecto IA primero para poder usar el Co-Piloto.' }]);
            return;
        }

        const userMsg: Message = { id: Date.now().toString(), role: 'user', content: textToSend };
        setMessages(prev => [...prev, userMsg]);
        if (!messageOverride) setInput('');
        setIsLoading(true);

        try {
            let contextStr = `Proceso: ${processContext?.workflows?.name}\nActividad Actual: ${processContext?.activities?.name}\nDatos del formulario actual: ${JSON.stringify(formData)}`;

            if (bimObject) {
                const currentStatus = bimStates?.[bimObject.id] || 'pending';
                contextStr += `\n\nCONTEXTO BIM SELECCIONADO:\nID Objeto (ExpressID): ${bimObject.id}\nNombre: ${bimObject.name}\nTipo IFC: ${bimObject.type}\nEstado Actual: ${currentStatus}\nPropiedades Crudas: ${JSON.stringify(bimObject.rawProps || {})}`;
            }

            if (bimStates && Object.keys(bimStates).length > 0) {
                contextStr += `\n\nRESUMEN DE ESTADOS BIM DEL PROCESO:\n${JSON.stringify(bimStates)}`;
            }

            const reply = await askAICopilot(userMsg.content, contextStr, apiKey);
            setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: reply }]);
        } catch (error: any) {
            setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: `Error: ${error.message}` }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed bottom-6 right-6 z-[70] flex flex-col items-end">
            {/* Main Toggle Button */}
            {!isOpen && (
                <button
                    onClick={() => setIsOpen(true)}
                    className="w-14 h-14 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-full shadow-2xl flex items-center justify-center text-white hover:scale-105 transition-all group border-2 border-white/20 dark:border-slate-800"
                >
                    <Sparkles className="w-6 h-6 group-hover:animate-pulse" />
                    <span className="absolute -top-2 -right-2 flex h-4 w-4">
                        <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-purple-400 opacity-75"></span>
                        <span className="relative inline-flex rounded-full h-4 w-4 bg-purple-500"></span>
                    </span>
                </button>
            )}

            {/* Chat Window */}
            {isOpen && (
                <div className="w-80 sm:w-96 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-800 overflow-hidden flex flex-col h-[500px] max-h-[80vh] animate-in slide-in-from-bottom-5 fade-in duration-300">
                    <div className="px-4 py-3 bg-gradient-to-r from-indigo-600 to-purple-600 text-white flex items-center justify-between shadow-md z-10">
                        <div className="flex items-center gap-2">
                            <Bot className="w-5 h-5" />
                            <h3 className="font-bold text-sm tracking-wide">{bimObject ? 'BIMind Assistant' : 'Co-Piloto IA'}</h3>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                            <X className="w-5 h-5" />
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 dark:bg-slate-900/50 custom-scrollbar">
                        {messages.map(msg => (
                            <div key={msg.id} className={clsx("flex flex-col max-w-[85%]", msg.role === 'user' ? "ml-auto items-end" : "mr-auto items-start")}>
                                <div className={clsx(
                                    "p-3 rounded-2xl text-xs sm:text-sm shadow-sm",
                                    msg.role === 'user'
                                        ? "bg-indigo-600 text-white rounded-tr-sm"
                                        : "bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 text-slate-700 dark:text-slate-200 rounded-tl-sm"
                                )}>
                                    {msg.content}
                                </div>
                            </div>
                        ))}
                        {isLoading && (
                            <div className="mr-auto items-start max-w-[85%] flex">
                                <div className="p-3 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl rounded-tl-sm shadow-sm flex items-center gap-2 text-indigo-500">
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    <span className="text-xs font-medium">Analizando...</span>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800">
                        <div className="relative flex items-center">
                            <input
                                type="text"
                                value={input}
                                onChange={e => setInput(e.target.value)}
                                onKeyDown={e => e.key === 'Enter' && handleSend()}
                                placeholder="Pregunta algo sobre esta tarea..."
                                className="w-full bg-slate-100 dark:bg-slate-800 border-transparent focus:border-indigo-500 focus:bg-white dark:focus:bg-slate-950 focus:ring-0 rounded-xl pl-4 pr-12 py-3 text-sm transition-all"
                            />
                            <button
                                onClick={() => handleSend()}
                                disabled={!input.trim() || isLoading}
                                className="absolute right-2 p-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg transition-colors disabled:opacity-50"
                            >
                                <Send className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState } from 'react';
import { X, Wand2, Loader2, Key, AlertCircle, Bot } from 'lucide-react';
import { cn } from '../utils/cn';
import type { AIGeneratedWorkflow } from '../services/aiService';

export type AIProviderName = 'openai' | 'gemini';

interface AIWorkflowGeneratorModalProps {
    isOpen: boolean;
    onClose: () => void;
    onGenerate: (data: AIGeneratedWorkflow, method: 'replace' | 'append') => void;
}

export function AIWorkflowGeneratorModal({ isOpen, onClose, onGenerate }: AIWorkflowGeneratorModalProps) {
    const [prompt, setPrompt] = useState('');
    const [provider, setProvider] = useState<AIProviderName>('openai');
    const [apiKey, setApiKey] = useState(localStorage.getItem('bpm_openai_key') || '');
    const [geminiKey, setGeminiKey] = useState(localStorage.getItem('bpm_gemini_key') || '');
    const [method, setMethod] = useState<'replace' | 'append'>('replace');
    const [isGenerating, setIsGenerating] = useState(false);
    const [error, setError] = useState<string | null>(null);

    if (!isOpen) return null;

    const currentKey = provider === 'openai' ? apiKey : geminiKey;

    const handleGenerate = async () => {
        if (!prompt.trim()) {
            setError("Por favor, ingresa una descripci├│n del proceso.");
            return;
        }
        if (!currentKey.trim()) {
            setError(`Se requiere una API Key de ${provider === 'openai' ? 'OpenAI' : 'Google Gemini'} v├ílida.`);
            return;
        }

        setError(null);
        setIsGenerating(true);

        try {
            // Guardar API keys
            if (provider === 'openai') localStorage.setItem('bpm_openai_key', apiKey);
            if (provider === 'gemini') localStorage.setItem('bpm_gemini_key', geminiKey);

            // Importar din├ímicamente el servicio
            const { generateWorkflowWithAI } = await import('../services/aiService');

            const generatedData = await generateWorkflowWithAI(prompt, currentKey, provider);
            onGenerate(generatedData, method);
            onClose();
            setPrompt('');
        } catch (err: any) {
            console.error("Error generating workflow:", err);
            setError(err.message || "Ocurri├│ un error al generar el flujo.");
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl w-full max-w-2xl overflow-hidden flex flex-col border border-indigo-500/20">

                {/* Header */}
                <div className="p-6 border-b border-gray-100 dark:border-gray-700/50 flex justify-between items-center bg-gradient-to-r from-indigo-50 to-white dark:from-indigo-900/20 dark:to-gray-800">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-indigo-100 dark:bg-indigo-900/50 rounded-lg text-indigo-600 dark:text-indigo-400">
                            <Wand2 className="w-6 h-6" />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-gray-900 dark:text-white">
                                Arquitecto IA
                            </h2>
                            <p className="text-sm text-gray-500 dark:text-gray-400">
                                Describe tu proceso y la IA crear├í el flujo por ti.
                            </p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                        disabled={isGenerating}
                    >
                        <X className="w-6 h-6" />
                    </button>
                </div>

                {/* Body */}
                <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh]">

                    {error && (
                        <div className="p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-xl text-sm flex items-start gap-3 border border-red-100 dark:border-red-900/30">
                            <AlertCircle className="w-5 h-5 shrink-0" />
                            <p>{error}</p>
                        </div>
                    )}

                    {/* Provider Selection */}
                    <div className="space-y-3">
                        <label className="text-sm font-medium text-gray-700 dark:text-gray-300">
                            Motor de Inteligencia Artificial
                        </label>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                type="button"
                                onClick={() => setProvider('openai')}
                                className={cn(
                                    "px-4 py-3 rounded-xl border text-sm font-medium transition-all flex items-center justify-center gap-2",
                                    provider === 'openai'
                                        ? "bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-700 text-indigo-700 dark:text-indigo-300 shadow-sm"
                                        : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700"
                                )}
                            >
                                <img src="https://upload.wikimedia.org/wikipedia/commons/4/4d/OpenAI_Logo.svg" className="w-4 h-4 dark:invert" alt="OpenAI" />
                                OpenAI (GPT-4)
                            </button>
                            <button
                                type="button"
                                onClick={() => setProvider('gemini')}
                                className={cn(
                                    "px-4 py-3 rounded-xl border text-sm font-medium transition-all flex items-center justify-center gap-2",
                                    provider === 'gemini'
                                        ? "bg-blue-50 dark:bg-blue-900/30 border-blue-200 dark:border-blue-700 text-blue-700 dark:text-blue-300 shadow-sm"
                                        : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700"
                                )}
                            >
                                <Bot className="w-5 h-5 text-blue-500" />
                                Google Gemini
                            </button>
                        </div>
                    </div>

                    {/* API Key */}
                    <div className="space-y-2">
                        <label className="flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-gray-300">
                            <Key className="w-4 h-4 text-gray-400" />
                            {provider === 'openai' ? 'OpenAI API Key' : 'Google Gemini API Key'}
                        </label>
                        <input
                            type="password"
                            value={provider === 'openai' ? apiKey : geminiKey}
                            onChange={(e) => provider === 'openai' ? setApiKey(e.target.value) : setGeminiKey(e.target.value)}
                            placeholder={provider === 'openai' ? "sk-..." : "AIzaSy..."}
                            className="w-full px-4 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all dark:text-white dark:placeholder-gray-500 text-sm"
                        />
                        <p className="text-[11px] text-gray-500 dark:text-gray-400">
                            Tu API key se guarda localmente en tu navegador de forma segura.
                        </p>
                    </div>

                    {/* Prompt */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex justify-between">
                            <span>Descripci├│n del Proceso</span>
                            <span className="text-xs text-indigo-600 dark:text-indigo-400">S├® tan detallado como quieras</span>
                        </label>
                        <textarea
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder="Ejemplo: Necesito un flujo para solicitud de vacaciones. El primer paso es que el empleado llene sus datos y fechas. El segundo paso es que su jefe lo apruebe o rechace. Si se aprueba, el tercer paso es que RRHH lo registre en el sistema."
                            className="w-full h-40 px-4 py-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all dark:text-white resize-none text-sm leading-relaxed"
                        />
                    </div>

                    {/* Method */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700 dark:text-gray-300">
                            Modo de Inserci├│n
                        </label>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                type="button"
                                onClick={() => setMethod('replace')}
                                className={cn(
                                    "px-4 py-3 rounded-xl border text-sm font-medium transition-all flex items-center justify-center gap-2",
                                    method === 'replace'
                                        ? "bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-700 text-indigo-700 dark:text-indigo-300 shadow-sm"
                                        : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700"
                                )}
                            >
                                <X className="w-4 h-4" />
                                Reemplazar Todo
                            </button>
                            <button
                                type="button"
                                onClick={() => setMethod('append')}
                                className={cn(
                                    "px-4 py-3 rounded-xl border text-sm font-medium transition-all flex items-center justify-center gap-2",
                                    method === 'append'
                                        ? "bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-700 text-indigo-700 dark:text-indigo-300 shadow-sm"
                                        : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700"
                                )}
                            >
                                <span className="text-lg leading-none">+</span>
                                A├▒adir al Final
                            </button>
                        </div>
                    </div>

                </div>

                {/* Footer */}
                <div className="p-6 border-t border-gray-100 dark:border-gray-700/50 bg-gray-50 dark:bg-gray-800/50 flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        disabled={isGenerating}
                        className="px-6 py-2.5 text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-xl transition-colors disabled:opacity-50"
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={handleGenerate}
                        disabled={isGenerating || !prompt.trim() || !apiKey.trim()}
                        className={cn(
                            "px-6 py-2.5 text-sm font-semibold text-white rounded-xl transition-all shadow-md flex items-center gap-2",
                            isGenerating
                                ? "bg-indigo-400 cursor-not-allowed"
                                : "bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400 hover:shadow-lg hover:-translate-y-0.5"
                        )}
                    >
                        {isGenerating ? (
                            <>
                                <Loader2 className="w-5 h-5 animate-spin" />
                                Generando Magia...
                            </>
                        ) : (
                            <>
                                <Wand2 className="w-5 h-5" />
                                Generar Flujo
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Mail, Lock, User as UserIcon, ArrowRight, ShieldCheck, Zap, LayoutDashboard, Database, Sparkles, KeyRound } from 'lucide-react';
import { PasswordResetModal } from './PasswordResetModal';

// Simple in-memory store for dev codes (in production, use a proper backend)
const devCodes = new Map<string, { code: string; timestamp: number }>();

export function Auth() {
    const [isLogin, setIsLogin] = useState(true);
    const [useMagicCode, setUseMagicCode] = useState(false);
    const [loading, setLoading] = useState(false);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [verificationCode, setVerificationCode] = useState('');
    const [name, setName] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState<string | null>(null);
    const [codeSent, setCodeSent] = useState(false);
    const [showResetModal, setShowResetModal] = useState(false);

    const generateCode = () => {
        return Math.floor(100000 + Math.random() * 900000).toString();
    };

    const handleSendCode = async () => {
        if (!email) {
            setError('Por favor ingresa tu email');
            return;
        }

        setLoading(true);
        setError(null);
        setSuccess(null);

        try {
            const code = generateCode();
            const timestamp = Date.now();

            // Store code with timestamp (expires in 10 minutes)
            devCodes.set(email.toLowerCase(), { code, timestamp });

            // Log to console for development
            console.log('ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü');
            console.log('­ƒöÉ C├ôDIGO DE VERIFICACI├ôN');
            console.log('ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü');
            console.log(`­ƒôº Email: ${email}`);
            console.log(`­ƒöæ C├│digo: ${code}`);
            console.log(`ÔÅ░ V├ílido por: 10 minutos`);
            console.log('ÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöüÔöü');

            setCodeSent(true);
            setSuccess(`┬íC├│digo enviado! Revisa la consola del navegador (F12) para ver tu c├│digo de 6 d├¡gitos.`);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleVerifyCode = async () => {
        setLoading(true);
        setError(null);

        try {
            const storedData = devCodes.get(email.toLowerCase());

            if (!storedData) {
                throw new Error('No se encontr├│ un c├│digo para este email. Solicita uno nuevo.');
            }

            // Check if code expired (10 minutes)
            const now = Date.now();
            const tenMinutes = 10 * 60 * 1000;
            if (now - storedData.timestamp > tenMinutes) {
                devCodes.delete(email.toLowerCase());
                throw new Error('El c├│digo ha expirado. Solicita uno nuevo.');
            }

            if (verificationCode !== storedData.code) {
                throw new Error('C├│digo incorrecto. Verifica e intenta de nuevo.');
            }

            // Code is valid, sign in with OTP
            const { error } = await supabase.auth.signInWithOtp({
                email,
                options: {
                    shouldCreateUser: true,
                },
            });

            if (error) throw error;

            // Clean up used code
            devCodes.delete(email.toLowerCase());
            setSuccess('┬íC├│digo verificado! Iniciando sesi├│n...');

        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (useMagicCode && !codeSent) {
            await handleSendCode();
            return;
        }

        if (useMagicCode && codeSent) {
            await handleVerifyCode();
            return;
        }

        setLoading(true);
        setError(null);
        setSuccess(null);

        try {
            if (isLogin) {
                // Password Login
                const { error } = await supabase.auth.signInWithPassword({
                    email,
                    password,
                });
                if (error) throw error;
            } else {
                // Sign Up
                const { error } = await supabase.auth.signUp({
                    email,
                    password,
                    options: {
                        data: {
                            full_name: name,
                        },
                    },
                });
                if (error) throw error;
                setSuccess('Registro exitoso. Revisa tu correo para confirmar la cuenta.');
            }
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
