                                <>
                                    {useMagicCode && !codeSent ? 'Enviar c├│digo' : (codeSent ? 'Verificar c├│digo' : (isLogin ? 'Entrar al Dashboard' : 'Crear mi cuenta'))}
                                    <ArrowRight className="w-5 h-5 group-hover:translate-x-2 transition-transform" />
                                </>
                            )}
                        </button>
                    </form>

                    <div className="mt-12 pt-12 border-t border-white/5">
                        <button
                            onClick={() => setIsLogin(!isLogin)}
                            className="w-full text-center group"
                        >
                            <span className="text-sm font-bold text-slate-500 group-hover:text-blue-400 transition-colors">
                                {isLogin ? '┬┐A├║n no tienes acceso? ' : '┬┐Ya eres miembro? '}
                            </span>
                            <span className="text-sm font-black text-white group-hover:text-blue-500 underline underline-offset-4 decoration-blue-500 transition-all ml-1">
                                {isLogin ? 'Reg├¡strate aqu├¡' : 'Inicia sesi├│n'}
                            </span>
                        </button>
                    </div>
                </div>
            </div>

            {/* Minimalist Footer */}
            <p className="absolute bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] z-20">
                &copy; {new Date().getFullYear()} BPM Manager ÔÇó High Productivity Platform
            </p>

            {/* Password Reset Modal */}
            <PasswordResetModal
                isOpen={showResetModal}
                onClose={() => setShowResetModal(false)}
            />
        </div>
    );
}

function Feature({ icon: Icon, label }: { icon: any, label: string }) {
    return (
        <div className="flex flex-col gap-2 p-4 bg-white/5 backdrop-blur-md rounded-[1.5rem] border border-white/10 hover:bg-white/10 transition-colors">
            <Icon className="w-5 h-5 text-blue-400" />
            <span className="text-[10px] font-black text-white uppercase tracking-wider">{label}</span>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { IfcViewer } from './IfcViewer';
import {
    PieChart, Pie, Cell, Tooltip, ResponsiveContainer
} from 'recharts';
import { Box, Layers, Activity, Info, ChevronRight, FileText } from 'lucide-react';
import { cn } from '../utils/cn';

interface BimState {
    express_id: number;
    status: 'completed' | 'processing' | 'delayed' | 'pending';
    process_id: string;
    process_name?: string;
}

interface IfcAttachment {
    id: string;
    file_name: string;
    file_path: string;
    process_id: string;
    process_number?: number;
}

export function BimReport() {
    const [ifcFiles, setIfcFiles] = useState<IfcAttachment[]>([]);
    const [selectedFile, setSelectedFile] = useState<IfcAttachment | null>(null);
    const [fileUrl, setFileUrl] = useState<string | null>(null);
    const [bimStates, setBimStates] = useState<Record<number, 'completed' | 'processing' | 'delayed' | 'pending'>>({});
    const [objectDetails, setObjectDetails] = useState<BimState[]>([]);
    const [selectedObject, setSelectedObject] = useState<any>(null);

    useEffect(() => {
        loadIfcFiles();
    }, []);

    useEffect(() => {
        if (selectedFile) {
            loadFileAndStates(selectedFile);
        }
    }, [selectedFile]);

    async function loadIfcFiles() {
        try {
            const { data, error } = await supabase
                .from('process_attachments')
                .select('*, process_instances(id, process_number, name)')
                .ilike('file_name', '%.ifc');

            if (error) throw error;

            const formattedFiles = data?.map((f: any) => ({
                id: f.id,
                file_name: f.file_name,
                file_path: f.file_path,
                process_id: f.process_instance_id,
                process_number: f.process_instances?.process_number,
                process_name: f.process_instances?.name
            })) || [];

            setIfcFiles(formattedFiles);
            if (formattedFiles.length > 0) {
                setSelectedFile(formattedFiles[0]);
            }
        } catch (err) {
            console.error('Error loading IFC files:', err);
        }
    }

    async function loadFileAndStates(file: IfcAttachment) {
        try {

            // 1. Get Signed URL for IFC
            const { data: urlData, error: urlError } = await supabase.storage
                .from('process-files')
                .createSignedUrl(file.file_path, 3600);

            if (urlError) throw urlError;
            setFileUrl(urlData.signedUrl);

            // 2. Load States for this process (and potentially others if we implement multi-process BIM)
            const { data: states, error: statesError } = await supabase
                .from('process_bim_states')
                .select('*, process_instances(name)')
                .eq('process_id', file.process_id);

            if (statesError) throw statesError;

            const statesMap: Record<number, 'completed' | 'processing' | 'delayed' | 'pending'> = {};
            const details: BimState[] = [];

            states?.forEach((s: any) => {
                statesMap[s.express_id] = s.status;
                details.push({
                    express_id: s.express_id,
                    status: s.status,
                    process_id: s.process_id,
                    process_name: s.process_instances?.name
                });
            });

            setBimStates(statesMap);
            setObjectDetails(details);
        } catch (err) {
            console.error('Error loading BIM details:', err);
        }
    }

    const stats = [
        { name: 'Completado', value: Object.values(bimStates).filter(s => s === 'completed').length, color: '#22c55e' },
        { name: 'En Proceso', value: Object.values(bimStates).filter(s => s === 'processing').length, color: '#3b82f6' },
        { name: 'Retrasado', value: Object.values(bimStates).filter(s => s === 'delayed').length, color: '#ef4444' },
        { name: 'Pendiente', value: Object.values(bimStates).filter(s => s === 'pending').length, color: '#f59e0b' },
    ].filter(s => s.value > 0);

    const totalObjects = Object.keys(bimStates).length;

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header / Selector */}
            <div className="bg-white dark:bg-slate-900/50 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-xl shadow-indigo-200 dark:shadow-none">
                        <Box className="w-7 h-7 text-white" />
                    </div>
                    <div>
                        <h2 className="text-xl font-black text-slate-900 dark:text-white leading-tight">M├®tricas BIM 4D</h2>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Visualizaci├│n de avance en modelo digital</p>
                    </div>
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto">
                    <div className="relative group flex-1 md:w-64">
                        <select
                            value={selectedFile?.id || ''}
                            onChange={(e) => {
                                const file = ifcFiles.find(f => f.id === e.target.value);
                                if (file) setSelectedFile(file);
                            }}
                            className="w-full h-12 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-800 rounded-2xl px-10 text-xs font-bold text-slate-700 dark:text-slate-200 outline-none focus:border-indigo-500 transition-all appearance-none cursor-pointer"
                        >
                            {ifcFiles.length === 0 && <option value="">No hay modelos IFC cargados</option>}
                            {ifcFiles.map(f => (
                                <option key={f.id} value={f.id}>{f.file_name} (#{f.process_number})</option>
                            ))}
                        </select>
                        <Layers className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none group-focus-within:text-indigo-500 transition-colors" />
                        <ChevronRight className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 rotate-90 pointer-events-none" />
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-4 gap-6 h-[700px]">
                {/* 3D Viewer */}
                <div className="xl:col-span-3 bg-white dark:bg-[#080a14] rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden relative">
                    {fileUrl ? (
                        <IfcViewer
                            fileUrl={fileUrl}
                            objectStates={bimStates}
                            onObjectSelected={(props) => {
                                const details = objectDetails.find(d => d.express_id === props.id);
                                setSelectedObject({ ...props, ...details });
                            }}
                        />
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-slate-400 p-10 text-center">
                            <Box className="w-16 h-16 mb-6 opacity-10" />
                            <h3 className="text-lg font-black uppercase tracking-widest mb-2">Seleccione un Modelo</h3>
                            <p className="text-xs font-medium max-w-xs leading-relaxed opacity-60">
                                Elija un archivo IFC de la lista superior para cargar la visualizaci├│n 3D y los estados de ejecuci├│n.
                            </p>
                        </div>
                    )}
                </div>

                {/* BIM Analytics Sidebar */}
                <div className="space-y-6 overflow-y-auto custom-scrollbar pr-2">
                    {/* Distribution Card */}
                    <div className="bg-white dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm">
                        <div className="flex items-center gap-2 mb-6">
                            <Activity className="w-4 h-4 text-indigo-600" />
                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Distribuci├│n de Estados</h3>
                        </div>

                        {stats.length > 0 ? (
                            <div className="h-48">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={stats}
                                            innerRadius={50}
                                            outerRadius={70}
                                            paddingAngle={5}
                                            dataKey="value"
                                        >
                                            {stats.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={entry.color} stroke="none" />
                                            ))}
                                        </Pie>
                                        <Tooltip
                                            contentStyle={{
                                                borderRadius: '12px',
                                                border: 'none',
                                                boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)',
                                                fontSize: '10px',
                                                fontWeight: 'bold'
                                            }}
                                        />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        ) : (
                            <div className="h-48 flex items-center justify-center text-slate-300 text-[10px] uppercase font-black italic">
                                Sin datos de estado
                            </div>
                        )}

                        <div className="grid grid-cols-2 gap-2 mt-4">
                            {stats.map(s => (
                                <div key={s.name} className="p-2 rounded-xl bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800">
                                    <div className="flex items-center gap-1.5 mb-1">
                                        <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: s.color }} />
                                        <span className="text-[8px] font-black text-slate-400 uppercase truncate">{s.name}</span>
                                    </div>
                                    <p className="text-sm font-black text-slate-700 dark:text-slate-200">{s.value}</p>
                                </div>
                            ))}
                            <div className="p-2 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 col-span-2">
                                <div className="flex items-center gap-2 mb-1">
                                    <Layers className="w-3 h-3 text-indigo-600" />
                                    <span className="text-[8px] font-black text-indigo-600 dark:text-indigo-400 uppercase">Total Objetos Controlados</span>
                                </div>
                                <p className="text-xl font-black text-indigo-700 dark:text-indigo-300">{totalObjects}</p>
                            </div>
                        </div>
                    </div>

                    {/* Object Inspector */}
                    <div className="bg-white dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm min-h-[300px]">
                        <div className="flex items-center gap-2 mb-6">
                            <Info className="w-4 h-4 text-blue-600" />
                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inspector de Objeto</h3>
                        </div>

                        {selectedObject ? (
                            <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
                                <div>
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1 leading-none">Tipo BIM</p>
                                    <h4 className="text-sm font-black text-slate-800 dark:text-white truncate">{selectedObject.type || 'Desconocido'}</h4>
                                </div>
                                <div className="p-3 bg-slate-50 dark:bg-slate-800/80 rounded-2xl border border-slate-100 dark:border-slate-700">
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1.5">ID Express</p>
                                    <p className="text-lg font-black text-blue-600 flex items-center gap-2">
                                        #{selectedObject.id}
                                        {selectedObject.status && (
                                            <span className={cn(
                                                "px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest border",
                                                selectedObject.status === 'completed' ? "bg-emerald-50 text-emerald-600 border-emerald-100" :
                                                    selectedObject.status === 'processing' ? "bg-blue-50 text-blue-600 border-blue-100" :
                                                        selectedObject.status === 'delayed' ? "bg-rose-50 text-rose-600 border-rose-100" :
                                                            "bg-amber-50 text-amber-600 border-amber-100"
                                            )}>
                                                {selectedObject.status}
                                            </span>
                                        )}
                                    </p>
                                </div>

                                {selectedObject.process_name ? (
                                    <div className="pt-2">
                                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1 leading-none">Vinculado a:</p>
                                        <div className="flex items-center gap-2 text-xs font-bold text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm">
                                            <FileText className="w-4 h-4 text-indigo-500" />
                                            {selectedObject.process_name}
                                        </div>
                                    </div>
                                ) : (
                                    <div className="p-4 bg-amber-50 dark:bg-amber-900/10 border border-amber-100 dark:border-amber-900/30 rounded-2xl">
                                        <p className="text-[10px] font-bold text-amber-700 dark:text-amber-400 leading-relaxed italic">
                                            Este objeto no tiene una actividad vinculada en el flujo de trabajo actual.
                                        </p>
                                    </div>
                                )}

                                <div className="mt-4 pt-4 border-t border-slate-50 dark:border-slate-800">
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2 leading-none">Propiedades IFC</p>
                                    <div className="max-h-40 overflow-y-auto custom-scrollbar space-y-2">
                                        {Object.entries(selectedObject.rawProps || {}).map(([key, val]: [string, any]) => (
                                            <div key={key} className="flex justify-between text-[10px] py-1 border-b border-slate-50 dark:border-slate-800/40">
                                                <span className="text-slate-400 font-bold uppercase">{key}</span>
                                                <span className="text-slate-700 dark:text-slate-300 font-black">{typeof val === 'object' ? val?.value || 'N/A' : String(val)}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-300 py-10 opacity-50">
                                <Box className="w-10 h-10 mb-2" />
                                <p className="text-[10px] font-black uppercase tracking-widest text-center">Selecciona un objeto<br />en el visor para inspeccionar</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Calendar as BigCalendar, dateFnsLocalizer } from 'react-big-calendar';
import { format, parse, startOfWeek, getDay } from 'date-fns';
import { es } from 'date-fns/locale';
import { supabase } from '../lib/supabase';
import { Filter, Download, Share2, Plus, X } from 'lucide-react';
import { cn } from '../utils/cn';
import { ProcessExecution } from './ProcessExecution';
import { ScheduleProcessModal } from './ScheduleProcessModal';
import { useScheduledProcesses } from '../hooks/useScheduledProcesses';
import { useAuth } from '../hooks/useAuth';
import 'react-big-calendar/lib/css/react-big-calendar.css';

const locales = { es };

const localizer = dateFnsLocalizer({
    format,
    parse,
    startOfWeek,
    getDay,
    locales,
});

interface CalendarEvent {
    id: string;
    title: string;
    start: Date;
    end: Date;
    resource: {
        processId?: string;
        workflowName: string;
        activityName?: string;
        status: 'overdue' | 'nearDue' | 'onTime' | 'scheduled';
        isRecurring?: boolean;
        scheduledProcess?: any;
    };
}

export function Calendar() {
    const { user } = useAuth();
    const { getScheduledProcesses } = useScheduledProcesses(user?.organization_id);
    const [events, setEvents] = useState<CalendarEvent[]>([]);
    const [workflows, setWorkflows] = useState<{ id: string; name: string }[]>([]);
    const [selectedWorkflowId, setSelectedWorkflowId] = useState<string | null>(null);
    const [selectedStatus, setSelectedStatus] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [selectedProcessId, setSelectedProcessId] = useState<string | null>(null);
    const [showScheduleModal, setShowScheduleModal] = useState(false);
    const [selectedDateSlot, setSelectedDateSlot] = useState<Date | null>(null);
    const [editingScheduledProcess, setEditingScheduledProcess] = useState<any | null>(null);
    const [exportedIds, setExportedIds] = useState<string[]>(() => {
        try {
            return JSON.parse(localStorage.getItem('bpm_exported_events') || '[]');
        } catch { return []; }
    });

    const newEventsCount = events.filter(e => !exportedIds.includes(e.id)).length;

    useEffect(() => {
        loadWorkflows();
        loadEvents();
    }, [selectedWorkflowId]);

    async function loadWorkflows() {
        const { data } = await supabase.from('workflows').select('id, name');
        if (data) setWorkflows(data);
    }

    async function loadEvents() {
        try {
            setLoading(true);

            let query = supabase
                .from('process_instances')
                .select(`
                    id,
                    name,
                    created_at,
                    workflow_id,
                    workflows (name),
                    activities (name, due_date_hours)
                `)
                .eq('status', 'active');

            if (selectedWorkflowId) {
                query = query.eq('workflow_id', selectedWorkflowId);
            }

            const { data: processes, error } = await query;
            if (error) throw error;

            const activeEvents: CalendarEvent[] = (processes || []).map((process: any) => {
                const dueHours = process.activities?.due_date_hours || 24;
                const createdAt = new Date(process.created_at);
                const dueDate = new Date(createdAt.getTime() + dueHours * 60 * 60 * 1000);

                const now = new Date();
                const hoursUntilDue = (dueDate.getTime() - now.getTime()) / (1000 * 60 * 60);
                let status: 'overdue' | 'nearDue' | 'onTime' | 'scheduled';
                if (hoursUntilDue < 0) status = 'overdue';
                else if (hoursUntilDue <= 4) status = 'nearDue';
                else status = 'onTime';

                return {
                    id: process.id,
                    title: process.name || process.workflows?.name || 'Proceso',
                    start: dueDate,
                    end: dueDate,
                    resource: {
                        processId: process.id,
                        workflowName: process.workflows?.name || 'N/A',
                        activityName: process.activities?.name || 'N/A',
                        status,
                    },
                };
            });

            // Load scheduled processes
            const scheduledData = await getScheduledProcesses();
            const scheduledEvents: CalendarEvent[] = (scheduledData || []).map(sp => ({
                id: sp.id,
                title: `[PROG] ${sp.name}`,
                start: new Date(sp.scheduled_at),
                end: new Date(new Date(sp.scheduled_at).getTime() + 60 * 60000),
                resource: {
                    workflowName: sp.workflows?.name || 'Plantilla',
                    status: 'scheduled',
                    isRecurring: sp.is_recurring,
                    scheduledProcess: sp // Store full object for editing
                }
            }));

            setEvents([...activeEvents, ...scheduledEvents]);
        } catch (err) {
            console.error('Error loading calendar events:', err);
        } finally {
            setLoading(false);
        }
    }

    const eventStyleGetter = (event: CalendarEvent) => {
        let backgroundColor = '#3b82f6'; // Blue (onTime)
        if (event.resource.status === 'overdue') backgroundColor = '#ef4444'; // Red
        else if (event.resource.status === 'nearDue') backgroundColor = '#f59e0b'; // Amber
        else if (event.resource.status === 'scheduled') backgroundColor = '#6366f1'; // Indigo/Violet

        return {
            style: {
                backgroundColor,
                borderRadius: '6px',
                opacity: 0.9,
                color: 'white',
                border: 'none',
                display: 'block',
                fontSize: '0.65rem',
                fontWeight: 600,
            },
        };
    };

    const handleSelectEvent = (event: CalendarEvent) => {
        if (event.resource.processId) {
            setSelectedProcessId(event.resource.processId);
        } else if (event.resource.scheduledProcess) {
            setEditingScheduledProcess(event.resource.scheduledProcess);
            setShowScheduleModal(true);
        }
    };

    const handleSelectSlot = ({ start }: { start: Date }) => {
        setSelectedDateSlot(start);
        setShowScheduleModal(true);
    };

    const handleSyncNewEvents = () => {
        const eventsToExport = events.filter(e => !exportedIds.includes(e.id));

        if (eventsToExport.length === 0) {
            alert('No hay eventos nuevos para sincronizar.');
            return;
        }

        let icsContent = [
            'BEGIN:VCALENDAR',
            'VERSION:2.0',
            'PRODID:-//BPM Manager//Event Calendar//ES',
            'CALSCALE:GREGORIAN',
            'METHOD:PUBLISH'
        ];

        eventsToExport.forEach(event => {
            const start = event.start.toISOString().replace(/-|:|\.\d+/g, '');
            const endDate = new Date(event.start.getTime() + 60 * 60000);
            const end = endDate.toISOString().replace(/-|:|\.\d+/g, '');

            icsContent.push(
                'BEGIN:VEVENT',
                `UID:${event.id}@bpm-manager`,
                `DTSTAMP:${new Date().toISOString().replace(/-|:|\.\d+/g, '')}`,
                `DTSTART:${start}`,
                `DTEND:${end}`,
                `SUMMARY:${event.title}`,
                `DESCRIPTION:Flujo: ${event.resource.workflowName}\\nEstado: ${event.resource.status}`,
                'END:VEVENT'
            );
        });

        icsContent.push('END:VCALENDAR');

        const blob = new Blob([icsContent.join('\r\n')], { type: 'text/calendar;charset=utf-8' });
        const link = document.createElement('a');
        link.href = window.URL.createObjectURL(blob);
        link.setAttribute('download', `sync-google-${new Date().getTime()}.ics`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

        // Update exported storage
        const newIds = [...exportedIds, ...eventsToExport.map(e => e.id)];
        setExportedIds(newIds);
        localStorage.setItem('bpm_exported_events', JSON.stringify(newIds));

        if (confirm(`Se han descargado ${eventsToExport.length} eventos nuevos. ┬┐Deseas abrir la p├ígina de importaci├│n de Google Calendar ahora?`)) {
            window.open('https://calendar.google.com/calendar/r/settings/export', '_blank');
        }
    };

    const exportToGoogleCalendar = () => {
        if (events.length === 0) {
            alert('No hay eventos para exportar');
            return;
        }

        // Export the first event or explain how to export individual ones if many
        if (events.length > 1) {
            const confirmAll = confirm(`Se han encontrado ${events.length} eventos. ┬┐Deseas exportar el primero a Google Calendar? (Para exportar todos, utiliza la opci├│n iCal)`);
            if (!confirmAll) return;
        }

        const event = events[0];
        const start = event.start.toISOString().replace(/-|:|\.\d+/g, '');
        const endDate = new Date(event.start.getTime() + 60 * 60000);
        const end = endDate.toISOString().replace(/-|:|\.\d+/g, '');

        const details = `Flujo: ${event.resource.workflowName}\nActividad: ${event.resource.activityName}\nEstado: ${event.resource.status}`;

        const url = `https://www.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(event.title)}&dates=${start}/${end}&details=${encodeURIComponent(details)}&sf=true&output=xml`;

        window.open(url, '_blank');
    };

    const filteredEvents = selectedStatus
        ? events.filter(e => e.resource?.status === selectedStatus)
        : events;

    return (
        <div className="p-4 max-w-7xl mx-auto h-full flex flex-col">
            {/* Ultra-Compact Action Bar */}
            <div className="mb-2 flex items-center justify-between gap-2 overflow-x-auto no-scrollbar">
                <div className="flex items-center gap-2 text-[9px] font-medium uppercase tracking-tighter shrink-0 cursor-pointer">
                    <button
                        onClick={() => setSelectedStatus(selectedStatus === 'overdue' ? null : 'overdue')}
                        className={cn(
                            "flex items-center gap-1 px-1.5 py-0.5 bg-rose-50 dark:bg-rose-900/20 text-rose-600 rounded-md border transition-all active:scale-95",
                            selectedStatus === 'overdue' ? "border-rose-500 ring-2 ring-rose-500/20" : "border-rose-100 dark:border-rose-800/30",
                            selectedStatus && selectedStatus !== 'overdue' && "opacity-40 grayscale-[0.5]"
                        )}
                    >
                        <div className="w-1.5 h-1.5 bg-rose-500 rounded-full animate-pulse"></div>
                        <span>Vencidas</span>
                    </button>
                    <button
                        onClick={() => setSelectedStatus(selectedStatus === 'nearDue' ? null : 'nearDue')}
                        className={cn(
                            "flex items-center gap-1 px-1.5 py-0.5 bg-amber-50 dark:bg-amber-900/20 text-amber-600 rounded-md border transition-all active:scale-95",
                            selectedStatus === 'nearDue' ? "border-amber-500 ring-2 ring-amber-500/20" : "border-amber-100 dark:border-amber-800/30",
                            selectedStatus && selectedStatus !== 'nearDue' && "opacity-40 grayscale-[0.5]"
                        )}
                    >
                        <div className="w-1.5 h-1.5 bg-amber-500 rounded-full"></div>
                        <span>Por Vencer</span>
                    </button>
                    <button
                        onClick={() => setSelectedStatus(selectedStatus === 'onTime' ? null : 'onTime')}
                        className={cn(
                            "flex items-center gap-1 px-1.5 py-0.5 bg-blue-50 dark:bg-blue-900/20 text-blue-600 rounded-md border transition-all active:scale-95",
                            selectedStatus === 'onTime' ? "border-blue-500 ring-2 ring-blue-500/20" : "border-blue-100 dark:border-blue-800/30",
                            selectedStatus && selectedStatus !== 'onTime' && "opacity-40 grayscale-[0.5]"
                        )}
                    >
                        <div className="w-1.5 h-1.5 bg-blue-500 rounded-full"></div>
                        <span>A Tiempo</span>
                    </button>
                    <button
                        onClick={() => setSelectedStatus(selectedStatus === 'scheduled' ? null : 'scheduled')}
                        className={cn(
                            "flex items-center gap-1 px-1.5 py-0.5 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-md border transition-all active:scale-95",
                            selectedStatus === 'scheduled' ? "border-indigo-500 ring-2 ring-indigo-500/20" : "border-indigo-100 dark:border-indigo-800/30",
                            selectedStatus && selectedStatus !== 'scheduled' && "opacity-40 grayscale-[0.5]"
                        )}
                    >
                        <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full"></div>
                        <span>Programados</span>
                    </button>

                    {selectedStatus && (
                        <button
                            onClick={() => setSelectedStatus(null)}
                            className="ml-1 text-[7px] text-slate-400 hover:text-blue-500 font-black flex items-center gap-0.5 transition-colors"
                        >
                            <X className="w-2 h-2" /> LIMPIAR
                        </button>
                    )}
                </div>

                <div className="flex items-center gap-1.5 shrink-0">
                    <div className="flex items-center gap-1.5 px-2 py-1 bg-slate-50 dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700 group transition-all">
                        <Filter className="w-3 h-3 text-slate-400" />
                        <select
                            value={selectedWorkflowId || ''}
                            onChange={(e) => setSelectedWorkflowId(e.target.value || null)}
                            className="bg-transparent text-[9px] font-black text-slate-700 dark:text-slate-300 outline-none cursor-pointer uppercase"
                        >
                            <option value="">TODOS</option>
                            {workflows.map((wf) => (
                                <option key={wf.id} value={wf.id}>{wf.name}</option>
                            ))}
                        </select>
                    </div>

                    <button
                        onClick={() => {
                            setSelectedDateSlot(new Date());
                            setShowScheduleModal(true);
                        }}
                        className="flex items-center gap-1 px-2.5 py-1 bg-blue-600 text-white rounded-lg text-[9px] font-black shadow-lg shadow-blue-200 dark:shadow-none hover:bg-blue-700 transition-all active:scale-95 uppercase"
                    >
                        <Plus className="w-3 h-3" />
                        Programar
                    </button>

                    <button
                        onClick={handleSyncNewEvents}
                        className={`flex items-center gap-1 px-2.5 py-1 rounded-lg text-[9px] font-black transition-all shadow-sm uppercase ${newEventsCount > 0
                            ? 'bg-blue-600 text-white shadow-blue-200'
                            : 'bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 text-slate-400'
                            }`}
                    >
                        <Download className="w-3 h-3" />
                        {newEventsCount > 0 ? `Sinc (${newEventsCount})` : 'Sinc'}
                    </button>

                    <button
                        onClick={() => exportToGoogleCalendar()}
                        className="flex items-center gap-1 px-2.5 py-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg text-[9px] font-black text-slate-500 hover:bg-slate-50 transition-all shadow-sm uppercase"
                    >
                        <Share2 className="w-3 h-3" />
                        Manual
                    </button>
                </div>
            </div>

            {/* Calendar */}
            <div className="bg-white dark:bg-slate-900 rounded-[1.2rem] border border-slate-200 dark:border-slate-800 shadow-sm p-2 flex-1" style={{ height: '480px' }}>
                <style>{`
                    .rbc-calendar { font-size: 10px; font-family: inherit; }
                    .rbc-event { padding: 1.5px 3.5px !important; margin: 0.5px 0 !important; border-radius: 3px !important; }
                    .rbc-month-row { min-height: 65px !important; }
                    .rbc-header { padding: 4px !important; font-weight: 800 !important; font-size: 9px !important; text-transform: uppercase; }
                    .rbc-button-link { font-size: 9px !important; font-weight: 700 !important; }
                    .rbc-toolbar-label { font-size: 12px !important; font-weight: 900 !important; text-transform: capitalize; }
                    .rbc-btn-group button { font-size: 10px !important; font-weight: 700 !important; text-transform: uppercase; padding: 3px 6px !important; }
                    .no-scrollbar::-webkit-scrollbar { display: none; }
                `}</style>
                {loading ? (
                    <div className="h-full flex items-center justify-center">
                        <div className="text-center">
                            <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
                            <p className="text-slate-500">Cargando eventos...</p>
                        </div>
                    </div>
                ) : (
                    <BigCalendar
                        localizer={localizer}
                        events={filteredEvents}
                        startAccessor="start"
                        endAccessor="end"
                        style={{ height: '100%' }}
                        eventPropGetter={eventStyleGetter}
                        onSelectEvent={handleSelectEvent}
                        onSelectSlot={handleSelectSlot}
                        selectable
                        culture="es"
                        messages={{
                            next: 'Siguiente',
                            previous: 'Anterior',
                            today: 'Hoy',
                            month: 'Mes',
                            week: 'Semana',
                            day: 'D├¡a',
                            agenda: 'Agenda',
                            date: 'Fecha',
                            time: 'Hora',
                            event: 'Evento',
                            noEventsInRange: 'No hay actividades en este rango',
                        }}
                    />
                )}
            </div>

            {/* Process Execution Modal */}
            {selectedProcessId && (
                <ProcessExecution
                    processId={selectedProcessId}
                    onClose={() => setSelectedProcessId(null)}
                    onComplete={() => {
                        setSelectedProcessId(null);
                        loadEvents(); // Reload events after completion
                    }}
                />
            )}

            {/* Schedule Process Modal */}
            {showScheduleModal && (
                <ScheduleProcessModal
                    workflows={workflows}
                    onClose={() => {
                        setShowScheduleModal(false);
                        setSelectedDateSlot(null);
                        setEditingScheduledProcess(null);
                    }}
                    onScheduled={() => {
                        loadEvents();
                    }}
                    initialDate={selectedDateSlot || undefined}
                    editProcess={editingScheduledProcess}
                />
            )}
        </div>
    );
}

import { useEffect } from 'react';
import {
    TrendingUp, Clock, Activity, CheckCircle2
} from 'lucide-react';
import { useDashboardStats } from '../hooks/useDashboardStats';
import { useDashboardAnalytics } from '../hooks/useDashboardAnalytics';
import { TaskInbox } from './TaskInbox';
import { WorkloadMap } from './WorkloadMap';
import { cn } from '../utils/cn';

export function Dashboard({ onAction, refreshTrigger }: { onAction?: (action: string, data?: any) => void, refreshTrigger?: number }) {
    const { instancesActive, instancesCompleted, historyCount, loading, refresh: statsRefresh } = useDashboardStats();
    const { userEfficiency, topActivities, refresh: analyticsRefresh } = useDashboardAnalytics();

    const refreshAll = () => {
        statsRefresh();
        analyticsRefresh();
    };

    useEffect(() => {
        const interval = setInterval(() => {
            refreshAll();
        }, 30000);
        return () => clearInterval(interval);
    }, [statsRefresh, analyticsRefresh]);

    useEffect(() => {
        if (refreshTrigger && refreshTrigger > 0) {
            refreshAll();
        }
    }, [refreshTrigger, statsRefresh, analyticsRefresh]);

    if (loading) {
        return (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-pulse">
                {[1, 2, 3].map((i) => (
                    <div key={i} className="h-24 bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800" />
                ))}
            </div>
        );
    }

    const formatTime = (hours: number) => {
        if (hours < 0.1) return Math.round(hours * 60) + 'm';
        return hours.toFixed(1) + 'h';
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-700 pb-10">
            {/* Header / Summary Row - Very Compact */}
            <div className="flex flex-col lg:flex-row gap-4 items-stretch lg:items-center">
                <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-3">
                    <StatCard
                        label="En Curso"
                        value={instancesActive.toString()}
                        color="blue"
                        icon={Activity}
                    />
                    <StatCard
                        label="Finalizados"
                        value={instancesCompleted.toString()}
                        color="emerald"
                        icon={CheckCircle2}
                    />
                    <StatCard
                        label="Log Acciones"
                        value={historyCount.toString()}
                        color="purple"
                        icon={TrendingUp}
                    />
                </div>
            </div>

            {/* Bandeja de Entrada - Main Area */}
            <div className="w-full">
                <TaskInbox
                    onAttendTask={(id) => onAction?.('attend-task', id)}
                    refreshTrigger={refreshTrigger}
                />
            </div>

            {/* Bottom Widgets - Grid Layout */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-20">
                {/* Efficiency Widget */}
                <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm h-full">
                    <div className="flex items-center gap-2 mb-6">
                        <Clock className="w-4 h-4 text-orange-500" />
                        <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-tighter">Mi Eficiencia en Atenci├│n</h3>
                    </div>

                    {userEfficiency.length > 0 ? (
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                            {userEfficiency.map((wf) => (
                                <div
                                    key={wf.workflow_name}
                                    className="p-3 bg-slate-50 dark:bg-slate-800/20 rounded-xl border border-slate-100 dark:border-slate-800/40 hover:border-orange-500/20 transition-colors"
                                >
                                    <div className="flex justify-between items-start mb-1.5 min-w-0">
                                        <p className="text-[9px] font-black text-slate-500 truncate">{wf.workflow_name}</p>
                                        <span className="text-[8px] font-black text-blue-600 bg-blue-50 dark:bg-blue-900/30 px-1 rounded whitespace-nowrap">{wf.count}</span>
                                    </div>
                                    <p className="text-lg font-black text-slate-900 dark:text-white">{formatTime(wf.avg_hours)}</p>
                                    <div className="mt-2 w-full h-1 bg-slate-200 dark:bg-slate-700/50 rounded-full overflow-hidden">
                                        <div
                                            className="h-full bg-orange-500 rounded-full"
                                            style={{ width: `${Math.min(100, (wf.avg_hours / 48) * 100)}%` }}
                                        />
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="h-[200px] flex flex-col items-center justify-center border-2 border-dashed border-slate-50 dark:border-slate-800 rounded-xl">
                            <p className="text-[10px] text-slate-400 font-bold uppercase italic tracking-widest">Sin datos hist├│ricos</p>
                        </div>
                    )}
                </div>

                {/* Workload Map Widget */}
                <WorkloadMap data={topActivities} />
            </div>
        </div>
    );
}

function StatCard({ label, value, color, icon: Icon = TrendingUp }: { label: string, value: string, color: 'blue' | 'orange' | 'emerald' | 'purple', icon?: any }) {
    const styles = {
        blue: "text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 border-blue-100/50 dark:border-blue-800/30",
        orange: "text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900/20 border-orange-100/50 dark:border-orange-800/30",
        emerald: "text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100/50 dark:border-emerald-800/30",
        purple: "text-purple-600 dark:text-purple-400 bg-purple-50 dark:bg-purple-900/20 border-purple-100/50 dark:border-purple-800/30",
    }[color];

    return (
        <div className={cn(
            "flex items-center gap-3 p-2.5 rounded-xl border transition-all duration-300",
            "bg-white dark:bg-slate-900/50 border-slate-100 dark:border-slate-800 shadow-sm",
            "hover:shadow-md hover:border-slate-200 dark:hover:border-slate-700 group cursor-default"
        )}>
            <div className={cn("p-1.5 rounded-lg border transition-transform group-hover:scale-110", styles)}>
                <Icon className="w-3 h-3" />
            </div>
            <div>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-0.5">{label}</p>
                <p className="text-base font-black text-slate-900 dark:text-white leading-none">{value}</p>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { X, Plus, Trash2, Edit2, Zap, Save, FileText, Settings2, FolderOpen } from 'lucide-react';
import { cn } from '../utils/cn';
import { FormPreviewModal } from './FormPreviewModal';
import type { WorkflowDetail, FieldDefinition, AutomatedAction, AutomatedActionType, ActionExecutionTiming } from '../types';

interface DetailsManagerModalProps {
    workflowId: string;
    details: WorkflowDetail[];
    setDetails: React.Dispatch<React.SetStateAction<WorkflowDetail[]>>;
    onClose: () => void;
    onSave: () => void;
}

export function DetailsManagerModal({ workflowId, details, setDetails, onClose, onSave }: DetailsManagerModalProps) {
    const [selectedDetailId, setSelectedDetailId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'general' | 'fields' | 'actions'>('general');
    const [showFormPreview, setShowFormPreview] = useState(false);

    const handleAddDetail = () => {
        const newDetail: WorkflowDetail = {
            id: crypto.randomUUID(),
            workflow_id: workflowId,
            name: 'Nueva Carpeta',
            description: '',
            fields: [],
            actions: []
        };
        setDetails(prev => [...prev, newDetail]);
        setSelectedDetailId(newDetail.id);
        setActiveTab('general');
    };

    const handleDeleteDetail = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirm('┬┐Eliminar esta carpeta? Se perder├í su configuraci├│n.')) {
            setDetails(prev => prev.filter(d => d.id !== id));
            if (selectedDetailId === id) setSelectedDetailId(null);
        }
    };

    // --- Fields Handlers ---
    const handleAddField = () => {
        if (!selectedDetailId) return;
        const newField: FieldDefinition = {
            id: crypto.randomUUID(),
            activity_id: `detail_${selectedDetailId}`, // pseudo activity id for details
            name: 'nuevo_campo',
            label: 'Nuevo Campo',
            type: 'text',
            required: false,
            order_index: (details.find(d => d.id === selectedDetailId)?.fields?.length || 0)
        };
        setDetails(prev => prev.map(d => d.id === selectedDetailId ? { ...d, fields: [...d.fields, newField] } : d));
    };

    const handleUpdateField = (fieldId: string, updates: Partial<FieldDefinition>) => {
        if (!selectedDetailId) return;
        setDetails(prev => prev.map(d =>
            d.id === selectedDetailId
                ? { ...d, fields: d.fields.map(f => f.id === fieldId ? { ...f, ...updates } : f) }
                : d
        ));
    };

    const handleDeleteField = (fieldId: string) => {
        if (!selectedDetailId) return;
        setDetails(prev => prev.map(d =>
            d.id === selectedDetailId
                ? { ...d, fields: d.fields.filter(f => f.id !== fieldId) }
                : d
        ));
    };

    // --- Actions Handlers ---
    const handleAddAction = (type: AutomatedActionType) => {
        if (!selectedDetailId) return;
        const newAction: AutomatedAction = {
            id: crypto.randomUUID(),
            type,
            name: `Nueva Acci├│n ${type.toUpperCase()}`,
            execution_timing: 'on_save_row',
            config: {}
        };
        setDetails(prev => prev.map(d =>
            d.id === selectedDetailId
                ? { ...d, actions: [...(d.actions || []), newAction] }
                : d
        ));
    };

    const handleUpdateAction = (actionId: string, updates: Partial<AutomatedAction>) => {
        if (!selectedDetailId) return;
        setDetails(prev => prev.map(d =>
            d.id === selectedDetailId
                ? { ...d, actions: (d.actions || []).map(act => act.id === actionId ? { ...act, ...updates } : act) }
                : d
        ));
    };

    return (
        <div className="fixed inset-0 z-[100] bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-950 rounded-[2.5rem] shadow-2xl w-full max-w-6xl max-h-[90vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-300">
                {/* Header */}
                <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/20">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center shadow-inner">
                            <FolderOpen className="w-6 h-6" />
                        </div>
                        <div>
                            <h2 className="text-xl font-black text-slate-900 dark:text-white tracking-tight">Gestor de Carpetas (Maestro-Detalle)</h2>
                            <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wider">Defina sub-estructuras repetibles para el flujo</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={() => { onSave(); onClose(); }} className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 transition-all font-black text-[12px] uppercase tracking-widest shadow-lg shadow-blue-500/20 active:scale-95">
                            <Save className="w-4 h-4" />
                            Aplicar Cambios
                        </button>
                        <button onClick={onClose} className="p-4 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-2xl transition-all">
                            <X className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                {/* Body Content */}
                <div className="flex-1 overflow-hidden flex">
                    {/* Sidebar: List of Details */}
                    <div className="w-80 border-r border-slate-100 dark:border-slate-800 bg-slate-50/30 dark:bg-slate-900/30 overflow-y-auto flex flex-col">
                        <div className="p-4">
                            <button onClick={handleAddDetail} className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl hover:border-indigo-500 text-slate-700 dark:text-slate-300 transition-all text-sm font-bold shadow-sm">
                                <Plus className="w-4 h-4" />
                                Nueva Carpeta
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2">
                            {details.map(detail => (
                                <div
                                    key={detail.id}
                                    onClick={() => setSelectedDetailId(detail.id)}
                                    className={cn(
                                        "p-3 rounded-xl border cursor-pointer transition-all group flex items-start gap-3",
                                        selectedDetailId === detail.id
                                            ? "bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800 shadow-sm"
                                            : "bg-white dark:bg-slate-950 border-slate-100 dark:border-slate-800 hover:border-indigo-200"
                                    )}
                                >
                                    <div className="mt-1 opacity-70">
                                        <FolderOpen className="w-4 h-4" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <h4 className={cn("font-bold text-sm truncate", selectedDetailId === detail.id ? "text-indigo-900 dark:text-indigo-100" : "text-slate-700 dark:text-slate-300")}>{detail.name}</h4>
                                        <p className="text-xs text-slate-500 truncate">{detail.fields.length} campos ÔÇó {detail.actions?.length || 0} acciones</p>
                                    </div>
                                    <button
                                        onClick={(e) => handleDeleteDetail(detail.id, e)}
                                        className="opacity-0 group-hover:opacity-100 p-1.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-lg transition-all"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            ))}
                            {details.length === 0 && (
                                <div className="text-center p-8 text-slate-400">
                                    <FolderOpen className="w-8 h-8 mx-auto mb-2 opacity-50" />
                                    <p className="text-sm">No hay carpetas</p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Main Content: Edit Detail */}
                    <div className="flex-1 flex flex-col overflow-hidden bg-white dark:bg-slate-950">
                        {selectedDetailId ? (
                            <>
                                {/* Tabs */}
                                <div className="flex gap-2 px-8 pt-4 bg-slate-50/50 dark:bg-slate-900/20 border-b border-slate-100 dark:border-slate-800/50">
