    );
}

import { useEffect, useRef, useState } from 'react';
import * as OBF from '@thatopen/components';
import * as THREE from 'three';
// @ts-ignore
import { FragmentsManager, BoundingBoxer, IfcLoader, Worlds, SimpleScene, SimpleCamera, SimpleRenderer } from '@thatopen/components';
import { Highlighter } from '@thatopen/components-front';

interface IfcViewerProps {
    fileUrl: string | File;
    onObjectSelected: (properties: any) => void;
    objectStates?: Record<number, 'completed' | 'processing' | 'delayed' | 'pending'>;
    className?: string;
}

export function IfcViewer({ fileUrl, onObjectSelected, objectStates, className = '' }: IfcViewerProps) {
    const containerRef = useRef<HTMLDivElement>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const componentsRef = useRef<OBF.Components | null>(null);
    const modelRef = useRef<any>(null);

    useEffect(() => {
        if (!componentsRef.current || !modelRef.current || !objectStates) return;

        const components = componentsRef.current;
        const model = modelRef.current;
        const highlighter = components.get(Highlighter) as any;

        const statusGroups: Record<string, number[]> = {
            completed: [],
            processing: [],
            delayed: [],
            pending: []
        };

        Object.entries(objectStates).forEach(([id, state]) => {
            if (statusGroups[state as string]) statusGroups[state as string].push(Number(id));
        });

        for (const [state, ids] of Object.entries(statusGroups)) {
            if (ids.length > 0) {
                try {
                    const selection = model.getFragmentMap(ids);
                    highlighter.highlight(state, selection);
                } catch (e) {
                    console.warn("Failed to update highlighter for state:", state, e);
                }
            }
        }
    }, [objectStates]);

    useEffect(() => {
        if (!containerRef.current) return;

        let components: OBF.Components;

        const initViewer = async () => {
            try {
                setIsLoading(true);
                setError(null);

                // 1. Initialize Components
                components = new OBF.Components();
                components.init();

                const fragments = components.get(FragmentsManager) as any;
                fragments.init("https://unpkg.com/@thatopen/fragments@3.3.6/dist/Worker/worker.mjs");

                componentsRef.current = components;

                // 2. Setup World & Camera
                const worlds = components.get(Worlds) as any;
                const world = worlds.create();

                world.scene = new SimpleScene(components);
                world.renderer = new SimpleRenderer(components, containerRef.current!);
                world.camera = new SimpleCamera(components);

                components.init(); // Wait for renderer sizing

                // Basic generic lighting
                world.scene.setup();
                world.scene.three.background = null; // Transparent/CSS controlled

                // 3. Setup IFC Loader
                const ifcLoader = components.get(IfcLoader) as any;
                ifcLoader.settings.wasm = {
                    path: "/wasm/",
                    absolute: false
                };
                await ifcLoader.setup(); // Downloads Web-IFC WASM

                // 4. Load File
                let buffer: Uint8Array;
                if (typeof fileUrl === 'string') {
                    const response = await fetch(fileUrl);
                    const arrayBuffer = await response.arrayBuffer();
                    buffer = new Uint8Array(arrayBuffer);
                } else {
                    const arrayBuffer = await fileUrl.arrayBuffer();
                    buffer = new Uint8Array(arrayBuffer);
                }

                // 5. Build Model
                const model = await ifcLoader.load(buffer);
                modelRef.current = model;
                world.scene.three.add(model);

                // Fit camera to model
                const bboxScanner = components.get(BoundingBoxer) as any;
                bboxScanner.add(model);
                const sphere = bboxScanner.getSphere();
                bboxScanner.reset();

                if (world.camera.controls) {
                    world.camera.controls.setLookAt(
                        sphere.center.x + sphere.radius * 2,
                        sphere.center.y + sphere.radius * 2,
                        sphere.center.z + sphere.radius * 2,
                        sphere.center.x,
                        sphere.center.y,
                        sphere.center.z,
                        true
                    );
                }

                // 6. Setup Raycaster / Selection & 4D Styles
                const highlighter = components.get(Highlighter) as any;
                highlighter.setup({ world });

                // Define 4D Status Styles
                const COMPLETED_COLOR = new (THREE as any).Color('#22c55e'); // Green 500
                const PROCESSING_COLOR = new (THREE as any).Color('#3b82f6'); // Blue 500
                const DELAYED_COLOR = new (THREE as any).Color('#ef4444');    // Red 500
                const PENDING_COLOR = new (THREE as any).Color('#f59e0b');    // Amber 500

                highlighter.add('completed', [COMPLETED_COLOR]);
                highlighter.add('processing', [PROCESSING_COLOR]);
                highlighter.add('delayed', [DELAYED_COLOR]);
                highlighter.add('pending', [PENDING_COLOR]);

                // Apply initial 4D colors if provided
                if (objectStates) {
                    const statusGroups: Record<string, number[]> = {
                        completed: [],
                        processing: [],
                        delayed: [],
                        pending: []
                    };

                    Object.entries(objectStates).forEach(([id, state]) => {
                        if (statusGroups[state]) statusGroups[state].push(Number(id));
                    });

                    for (const [state, ids] of Object.entries(statusGroups)) {
                        if (ids.length > 0) {
                            const selection = model.getFragmentMap(ids);
                            highlighter.highlight(state, selection);
                        }
                    }
                }


                highlighter.events.select.onHighlight.add(async (selection: any) => {
                    const fragmentId = Object.keys(selection)[0];
                    if (!fragmentId) return;

                    const expressIds = selection[fragmentId];
                    const id = [...expressIds][0]; // get first selected ID

                    if (id !== undefined && model.getItemsData) {
                        try {
                            const data = await model.getItemsData([id], { attributesDefault: true });
                            if (data && data.length > 0) {
                                const props = data[0].attributes || {};
                                onObjectSelected({
                                    id: props.expressID || id,
                                    name: props.Name?.value || props.name || 'Objeto BIM',
                                    type: props.ObjectType?.value || props.type || 'Tipo Desconocido',
                                    rawProps: props
                                });
                            }
                        } catch (err) {
                            console.error("Error getting item properties", err);
                        }
                    }
                });

                setIsLoading(false);
            } catch (err: any) {
                console.error("IFC Loading error", err);
                setError(err.message || "Failed to load IFC model");
                setIsLoading(false);
            }
        };

        initViewer();

        return () => {
            if (components) {
                components.dispose();
                componentsRef.current = null;
                modelRef.current = null;
            }
        };
    }, [fileUrl]);

    return (
        <div className={`relative w-full h-full overflow-hidden bg-slate-900 rounded-xl ${className}`}>
            {isLoading && (
                <div className="absolute inset-0 flex items-center justify-center bg-slate-900/80 z-10">
                    <div className="flex flex-col items-center">
                        <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4" />
                        <p className="text-white font-bold tracking-widest text-xs uppercase">Cargando Modelo BIM...</p>
                    </div>
                </div>
            )}

            {error && (
                <div className="absolute inset-0 flex items-center justify-center bg-rose-900/80 z-10">
                    <div className="text-white text-center max-w-sm px-4">
                        <p className="font-bold text-sm mb-2 uppercase tracking-widest text-rose-300">Error de BIM</p>
                        <p className="text-xs opacity-80">{error}</p>
                    </div>
                </div>
            )}

            <div ref={containerRef} className="w-full h-full outline-none" />

            <div className="absolute bottom-4 left-4 right-4 flex justify-between pointer-events-none">
                <div className="bg-slate-900/60 backdrop-blur text-white text-[10px] px-3 py-1.5 rounded-lg border border-slate-700 font-bold uppercase tracking-widest pointer-events-auto">
                    3D Viewer Activo
                </div>
                <div className="bg-indigo-600/90 text-white text-[10px] px-3 py-1.5 rounded-lg font-bold uppercase tracking-widest shadow-lg pointer-events-auto cursor-help" title="Haz clic en un objeto del modelo (puerta, ventana, etc.) para ver sus propiedades BIM.">
                    Click para inspeccionar
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { Search, Loader2, X, Check } from 'lucide-react';
import { cn } from '../utils/cn';
import type { FieldDefinition } from '../types';
import { supabase } from '../lib/supabase';

interface InteractiveLookupProps {
    field: FieldDefinition;
    value: any;
    onChange: (value: any) => void;
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    formData: Record<string, any>;
    setFormData: React.Dispatch<React.SetStateAction<Record<string, any>>>;
    error?: string;
}

export function InteractiveLookup({ field, value, onChange, setFormData, error }: InteractiveLookupProps) {
    const [searchTerm, setSearchTerm] = useState('');
    const [results, setResults] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const [selectedRecord, setSelectedRecord] = useState<any | null>(null);
    const [fetchError, setFetchError] = useState<string | null>(null);

    const wrapperRef = useRef<HTMLDivElement>(null);
    const config = field.lookup_config;

    // Cargar registro seleccionado inicial si hay value
    useEffect(() => {
        if (value && !selectedRecord && (config?.url || config?.type === 'database')) {
            // En un entorno real, aqu├¡ podr├¡amos hacer un GET por ID para popular selectedRecord
            // Por ahora, solo mostraremos el ID
            setSearchTerm(String(value));
        }
    }, [value, config, selectedRecord]);

    // Debounce de b├║squeda
    useEffect(() => {
        if (!isOpen || !config?.url) return;

        const delayDebounceFn = setTimeout(async () => {
            if (searchTerm.length < 2 && (!config.search_param && !config.search_column)) return;

            setIsLoading(true);
            setFetchError(null);

            try {
                if (config.type === 'database') {
                    // --- Database Catalog Search using RPC ---
                    if (!config.table_name || !config.search_column) {
                        throw new Error("Configuraci├│n de base de datos incompleta");
                    }

                    // Ensure value_field is included in return columns even if not displayed
                    const returnColumns = new Set(config.display_fields || []);
                    if (config.value_field) returnColumns.add(config.value_field);
                    if (config.mapping) {
                        Object.keys(config.mapping).forEach(k => returnColumns.add(k));
                    }

                    const { data, error } = await supabase.rpc('search_dynamic_table', {
                        p_table_name: config.table_name,
                        p_search_column: config.search_column,
                        p_search_term: searchTerm,
                        p_return_columns: Array.from(returnColumns)
                    });

                    if (error) throw error;

                    // The RPC returns { result_row: jsonb }
                    setResults(data ? data.map((d: any) => d.result_row) : []);

                } else {
                    // --- Legacy REST API Search ---
                    if (!config.url) throw new Error("URL de API no configurada");

                    const targetUrl = new URL(config.url);
                    if (config.method === 'GET' && config.search_param && searchTerm) {
                        targetUrl.searchParams.append(config.search_param, searchTerm);
                    }

                    const options: RequestInit = {
                        method: config.method || 'GET',
                        headers: {
                            'Content-Type': 'application/json',
                            ...(config.headers || {})
                        }
                    };

                    if (config.method === 'POST' && config.search_param) {
                        options.body = JSON.stringify({ [config.search_param]: searchTerm });
                    }

                    const response = await fetch(targetUrl.toString(), options);

                    if (!response.ok) {
                        throw new Error(`Error HTTP: ${response.status}`);
                    }

                    const data = await response.json();

                    // Navegar result_path si existe
                    let finalData = data;
                    if (config.result_path) {
                        const paths = config.result_path.split('.');
                        for (const p of paths) {
                            if (finalData && typeof finalData === 'object' && p in finalData) {
                                finalData = finalData[p];
                            } else {
                                finalData = []; // Path no encontrado
                                break;
                            }
                        }
                    }

                    if (Array.isArray(finalData)) {
                        setResults(finalData);
                    } else {
                        setResults([finalData]); // Intentar envolver en array si no lo es
                    }
                }

            } catch (err: any) {
                console.error("Lookup error:", err);
                setFetchError(err.message || 'Error consultando datos');
                setResults([]);
            } finally {
                setIsLoading(false);
            }

        }, 500);

        return () => clearTimeout(delayDebounceFn);
    }, [searchTerm, isOpen, config]);

    // Cerrar popover al clickear afuera
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleSelect = (row: any) => {
        if (!config || !config.value_field) return;

        const selectedValue = row[config.value_field];
        setSelectedRecord(row);

        // Formatear t├®rmino de b├║squeda para mostrar algo lindo (ej: concatenar display_fields)
        const displayData = config.display_fields?.map(df => row[df]).filter(Boolean).join(' - ');
        setSearchTerm(displayData || String(selectedValue));

        onChange(selectedValue);
        setIsOpen(false);

        // Aplicar mapeos extra
        if (config.mapping) {
            const mappedUpdates: Record<string, any> = {};
            for (const [resKey, formKey] of Object.entries(config.mapping)) {
                if (row[resKey] !== undefined) {
                    mappedUpdates[formKey] = row[resKey];
                }
            }
            if (Object.keys(mappedUpdates).length > 0) {
                setFormData(prev => ({ ...prev, ...mappedUpdates }));
            }
        }
    };

    const handleClear = (e: React.MouseEvent) => {
        e.stopPropagation();
        setSearchTerm('');
        setSelectedRecord(null);
        onChange('');
        setResults([]);

        // Limpiar mapeos si es necesario - Podr├¡a ser destructivo, depende del req negocio.
        // Por ahora solo limpiamos el campo principal.
    };

    return (
        <div className="relative" ref={wrapperRef}>
            <div
                className={cn(
                    "flex items-center gap-2 w-full p-2.5 rounded-2xl border-2 bg-white dark:bg-slate-900 transition-all cursor-text",
                    isOpen
                        ? "border-indigo-500 shadow-lg shadow-indigo-500/20"
                        : error ? "border-rose-400" : "border-slate-200 dark:border-slate-800 focus-within:border-indigo-500"
                )}
                onClick={() => setIsOpen(true)}
            >
                <div className="flex-shrink-0 text-indigo-500">
                    {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Search className="w-5 h-5" />}
                </div>

                <input
                    type="text"
                    value={searchTerm}
                    onChange={(e) => {
                        setSearchTerm(e.target.value);
                        if (!isOpen) setIsOpen(true);
                    }}
                    onFocus={() => setIsOpen(true)}
                    placeholder={field.placeholder || "Buscar..."}
                    className="flex-1 min-w-0 bg-transparent outline-none text-sm font-bold text-slate-700 dark:text-slate-200 placeholder-slate-400"
                />

                {(searchTerm || value) && (
                    <button
                        onClick={handleClear}
                        className="p-1 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg transition-colors"
                    >
                        <X className="w-4 h-4" />
                    </button>
                )}
            </div>

            {/* Dropdown Results */}
            {isOpen && (
                <div className="absolute z-50 w-full mt-2 bg-white dark:bg-slate-900 rounded-2xl border flex flex-col border-slate-200 dark:border-slate-800 shadow-2xl overflow-hidden max-h-[300px]">
                    {isLoading && results.length === 0 && (
                        <div className="p-4 text-center text-sm font-medium text-slate-500">
                            Buscando...
                        </div>
                    )}

                    {fetchError && (
                        <div className="p-4 text-center text-sm font-medium text-rose-500">
                            {fetchError}
                        </div>
                    )}

                    {!isLoading && !fetchError && results.length === 0 && searchTerm.length >= 2 && (
                        <div className="p-4 text-center text-sm font-medium text-slate-500">
                            No se encontraron resultados
                        </div>
                    )}

                    {results.length > 0 && (
                        <div className="overflow-y-auto w-full">
                            <table className="w-full text-left text-sm">
                                <thead className="bg-slate-50 dark:bg-slate-800/50 sticky top-0 border-b border-slate-100 dark:border-slate-700">
                                    <tr>
                                        {config?.display_fields?.map((df, i) => (
                                            <th key={i} className="px-4 py-2 text-[10px] font-black uppercase text-slate-400 tracking-wider">
                                                {df}
                                            </th>
                                        ))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50 dark:divide-slate-800/50">
                                    {results.map((row, i) => {
                                        const isSelected = value === row[config?.value_field || ''];
                                        return (
                                            <tr
                                                key={i}
                                                onClick={() => handleSelect(row)}
                                                className={cn(
                                                    "cursor-pointer transition-colors",
                                                    isSelected
                                                        ? "bg-indigo-50 dark:bg-indigo-900/30"
                                                        : "hover:bg-slate-50 dark:hover:bg-slate-800/50"
                                                )}
                                            >
                                                {config?.display_fields?.map((df, j) => (
                                                    <td key={j} className="px-4 py-3 text-slate-700 dark:text-slate-300">
                                                        <div className="flex items-center gap-2">
                                                            {j === 0 && isSelected && <Check className="w-4 h-4 text-indigo-500 flex-shrink-0" />}
                                                            <span className={cn(j === 0 && isSelected && "font-bold text-indigo-700 dark:text-indigo-300")}>
                                                                {row[df]}
                                                            </span>
                                                        </div>
                                                    </td>
                                                ))}
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

