                    <ChevronDown className={cn(
                        "w-3 h-3 transition-transform duration-300",
                        isOpen ? "rotate-180 text-blue-500" : "text-slate-300 dark:text-slate-700"
                    )} />
                </button>
                <div className={cn(
                    "overflow-hidden transition-all duration-300 ease-in-out",
                    isOpen ? "max-h-96 opacity-100 mt-1" : "max-h-0 opacity-0"
                )}>
                    <div className="pl-2 space-y-1 border-l-2 border-slate-50 dark:border-slate-800 ml-4 py-1">
                        {children}
                    </div>
                </div>
            </>
        ) : (
            <div className="flex flex-col items-center gap-2 py-2">
                <div className="w-8 h-px bg-slate-100 dark:bg-slate-800 my-1" />
                {children}
            </div>
        )}
    </div>
);

interface SidebarProps {
    activeSection: string;
    onSectionChange: (section: string) => void;
    onNewProcess?: () => void;
    isCollapsed?: boolean;
}

export function Sidebar({ activeSection, onSectionChange, onNewProcess, isCollapsed }: SidebarProps) {
    const { user, signOut, switchOrganization } = useAuth();
    const [openSections, setOpenSections] = useState<Set<string>>(new Set(['operaciones', 'herramientas']));

    const toggleSection = (section: string) => {
        const newOpen = new Set(openSections);
        if (newOpen.has(section)) {
            newOpen.delete(section);
        } else {
            newOpen.add(section);
        }
        setOpenSections(newOpen);
    };

    const isOperacionesActive = ['new-process', 'search'].includes(activeSection);
    const isHerramientasActive = ['calendar', 'reports', 'monitor'].includes(activeSection);
    const isConfigActive = ['workflows', 'users', 'organization', 'accounts', 'parameters', 'providers', 'orgchart'].includes(activeSection);

    return (
        <aside className={cn(
            "bg-white dark:bg-[#080a14] border-r border-slate-100 dark:border-slate-800 flex flex-col sticky top-0 h-screen z-20 transition-all duration-300 ease-in-out",
            isCollapsed ? "w-20" : "w-64"
        )}>
            <div className={cn("p-5 h-full flex flex-col", isCollapsed && "p-4")}>
                <div className={cn("mb-6 relative group", isCollapsed && "mb-5")}>
                    <button className={cn(
                        "w-full flex items-center gap-3 p-2 -ml-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors text-left",
                        isCollapsed && "ml-0 justify-center p-0"
                    )}>
                        <div className="w-9 h-9 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-100 flex-shrink-0">
                            <GitBranch className="text-white w-5 h-5" />
                        </div>
                        {!isCollapsed && (
                            <>
                                <div className="flex-1 overflow-hidden">
                                    <h1 className="text-sm font-black text-slate-900 dark:text-slate-100 leading-tight truncate">
                                        {user?.available_organizations?.find(o => o.id === user.organization_id)?.name || 'BPM FLOW'}
                                    </h1>
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider truncate">
                                        {user?.available_organizations?.find(o => o.id === user.organization_id)?.role || 'Viewer'}
                                    </p>
                                </div>
                                <ChevronRight className="w-4 h-4 text-slate-300 group-hover:rotate-90 transition-transform" />
                            </>
                        )}
                    </button>

                    {/* Dropdown - only show if not collapsed or handle differently */}
                    {!isCollapsed && (
                        <div className="absolute top-full left-0 w-full mt-2 bg-white dark:bg-[#0d111d] border border-slate-100 dark:border-slate-800 rounded-[1.5rem] shadow-xl dark:shadow-2xl dark:shadow-slate-950 p-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-50 backdrop-blur-xl">
                            <p className="text-[10px] font-black text-slate-400 dark:text-slate-600 uppercase tracking-[0.2em] px-3 py-3">Mis Organizaciones</p>
                            <div className="space-y-1">
                                {user?.available_organizations?.map(org => (
                                    <button
                                        key={org.id}
                                        onClick={() => switchOrganization(org.id)}
                                        className={cn(
                                            "w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-xs font-bold transition-all active:scale-95",
                                            org.id === user?.organization_id
                                                ? "bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 border border-blue-100 dark:border-blue-800"
                                                : "text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-slate-100 border border-transparent"
                                        )}
                                    >
                                        <div className={cn(
                                            "w-2 h-2 rounded-full",
                                            org.id === user?.organization_id ? "bg-blue-500" : "bg-slate-300 dark:bg-slate-700"
                                        )} />
                                        {org.name}
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                <nav className="space-y-4 flex-1">
                    <SidebarItem
                        icon={LayoutDashboard}
                        label="Dashboard"
                        active={activeSection === 'dashboard'}
                        onClick={() => onSectionChange('dashboard')}
                        isCollapsed={isCollapsed}
                    />

                    <div className="space-y-3">
                        <CollapsibleSection
                            label="Operaciones"
                            isOpen={openSections.has('operaciones')}
                            onToggle={() => toggleSection('operaciones')}
                            isActive={isOperacionesActive}
                            isCollapsed={isCollapsed}
                        >
                            <SidebarItem
                                icon={PlusCircle}
                                label="Nuevo Tr├ímite"
                                onClick={onNewProcess}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Search}
                                label="Buscar Tr├ímites"
                                active={activeSection === 'search'}
                                onClick={() => onSectionChange('search')}
                                isCollapsed={isCollapsed}
                            />
                        </CollapsibleSection>

                        <CollapsibleSection
                            label="Herramientas"
                            isOpen={openSections.has('herramientas')}
                            onToggle={() => toggleSection('herramientas')}
                            isActive={isHerramientasActive}
                            isCollapsed={isCollapsed}
                        >
                            <SidebarItem
                                icon={Calendar}
                                label="Calendario"
                                active={activeSection === 'calendar'}
                                onClick={() => onSectionChange('calendar')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={BarChart3}
                                label="Reportes"
                                active={activeSection === 'reports'}
                                onClick={() => onSectionChange('reports')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Zap}
                                label="Monitor de API"
                                active={activeSection === 'monitor'}
                                onClick={() => onSectionChange('monitor')}
                                isCollapsed={isCollapsed}
                            />
                        </CollapsibleSection>

                        <CollapsibleSection
                            label="Configuraci├│n"
                            isOpen={openSections.has('configuracion')}
                            onToggle={() => toggleSection('configuracion')}
                            isActive={isConfigActive}
                            isCollapsed={isCollapsed}
                        >
                            <SidebarItem
                                icon={GitBranch}
                                label="Mis Flujos"
                                active={activeSection === 'workflows'}
                                onClick={() => onSectionChange('workflows')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Users}
                                label="Usuarios"
                                active={activeSection === 'users'}
                                onClick={() => onSectionChange('users')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Building2}
                                label="Mi Empresa"
                                active={activeSection === 'organization'}
                                onClick={() => onSectionChange('organization')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Settings}
                                label="Par├ímetros"
                                active={activeSection === 'parameters'}
                                onClick={() => onSectionChange('parameters')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Package}
                                label="Proveedores"
                                active={activeSection === 'providers'}
                                onClick={() => onSectionChange('providers')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Network}
                                label="Organigrama"
                                active={activeSection === 'orgchart'}
                                onClick={() => onSectionChange('orgchart')}
                                isCollapsed={isCollapsed}
                            />
                            <SidebarItem
                                icon={Fingerprint}
                                label="Cuentas"
                                active={activeSection === 'accounts'}
                                onClick={() => onSectionChange('accounts')}
                                isCollapsed={isCollapsed}
                            />
                        </CollapsibleSection>
                    </div>
                </nav>

                <div className={cn("pt-4 border-t border-slate-50 dark:border-slate-800", isCollapsed && "mt-auto pt-2")}>
                    <button
                        onClick={signOut}
                        title={isCollapsed ? "Cerrar Sesi├│n" : undefined}
                        className={cn(
                            "w-full flex items-center gap-3 p-4 text-slate-400 dark:text-slate-500 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-2xl transition-all group",
                            isCollapsed && "p-2 justify-center"
                        )}
                    >
                        <LogOut className="w-4.5 h-4.5 group-hover:rotate-12 transition-transform" />
                        {!isCollapsed && <span className="font-bold text-[13px]">Cerrar Sesi├│n</span>}
                    </button>
                </div>
            </div>
        </aside>
    );
}

interface MainLayoutProps {
    children: ReactNode;
    activeSection: string;
    onSectionChange: (section: string) => void;
    onNewProcess?: () => void;
}

export function MainLayout({ children, activeSection, onSectionChange, onNewProcess }: MainLayoutProps) {
    const { user } = useAuth();
    const { profile, loading: profileLoading } = useProfile(user?.id);
    const { theme, toggleTheme } = useTheme();
    const [isCollapsed, setIsCollapsed] = useState(false);

    return (
        <div className="flex h-screen overflow-hidden bg-slate-200/40 dark:bg-[#02040a]">
            <Sidebar
                activeSection={activeSection}
                onSectionChange={onSectionChange}
                onNewProcess={onNewProcess}
                isCollapsed={isCollapsed}
            />
            <main className="flex-1 overflow-y-auto custom-scrollbar">
                <header className="h-16 border-b border-slate-100 dark:border-slate-800 bg-white/80 dark:bg-[#080a14]/80 backdrop-blur-xl px-6 flex items-center justify-between sticky top-0 z-40 transition-all">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => setIsCollapsed(!isCollapsed)}
                            className="p-2 -ml-2 rounded-xl text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all active:scale-95"
                            title={isCollapsed ? "Expandir Men├║" : "Contraer Men├║"}
                        >
                            <Menu className="w-5 h-5" />
                        </button>
                        <div className="flex items-center gap-3">
                            {(() => {
                                const icons: Record<string, any> = {
                                    dashboard: LayoutDashboard,
                                    workflows: GitBranch,
                                    users: Users,
                                    search: Search,
                                    reports: BarChart3,
                                    calendar: Calendar,
                                    providers: Package,
                                    orgchart: Network,
                                    accounts: Fingerprint,
                                    monitor: Zap,
                                    organization: Building2,
                                    settings: ChevronRight
                                };
                                const Icon = icons[activeSection] || ChevronRight;
                                return (
                                    <div className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-xl">
                                        <Icon className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                                    </div>
                                );
                            })()}
                            <div>
                                <p className="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] mb-0.5 leading-none">M├│dulo Principal</p>
                                <h2 className="text-lg font-black text-slate-900 dark:text-white capitalize leading-none">
                                    {activeSection === 'orgchart' ? 'Organigrama' :
                                        activeSection === 'workflows' ? 'Flujos de Trabajo' :
                                            activeSection === 'search' ? 'Mis Tr├ímites' :
                                                activeSection === 'calendar' ? 'Calendario' :
                                                    activeSection === 'users' ? 'Colaboradores' :
                                                        activeSection === 'accounts' ? 'Cuentas de Sistema' :
                                                            activeSection === 'monitor' ? 'Monitor de API' :
                                                                activeSection}
                                </h2>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        {/* Theme Toggle */}
                        <button
                            onClick={toggleTheme}
                            className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
                            title={theme === 'light' ? 'Activar modo oscuro' : 'Activar modo claro'}
                        >
                            {theme === 'light' ? (
                                <Moon className="w-5 h-5 text-slate-600" />
                            ) : (
                                <Sun className="w-5 h-5 text-slate-400" />
                            )}
                        </button>

                        <div className="text-right mr-2">
                            {profileLoading ? (
                                <div className="h-4 w-24 bg-slate-100 dark:bg-slate-800 animate-pulse rounded-full" />
                            ) : (
                                <>
                                    <p className="text-sm font-black text-slate-900 dark:text-white leading-none mb-1">{profile?.full_name || 'Usuario'}</p>
                                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{profile?.role || 'Viewer'}</p>
                                </>
                            )}
                        </div>
                        <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-blue-600 to-blue-700 flex items-center justify-center text-white font-black shadow-lg shadow-blue-200 dark:shadow-blue-900/20 border-2 border-white dark:border-slate-800 relative group/avatar">
                            {profile?.full_name?.[0]?.toUpperCase() || 'U'}
                            <div className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-emerald-500 border-2 border-white dark:border-slate-800 rounded-full" />
                        </div>
                    </div>
                </header>
                <div className="p-5">
                    {children}
                </div>
            </main>
        </div>
    );
}

import { Building2, Shield, CreditCard, Users, CheckCircle2, Plus, Settings, Trash2, Package } from 'lucide-react';
import { useAuth } from '../hooks/useAuth';
import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import type { Organization } from '../types';

export function OrganizationSettings({ onlyParameters }: { onlyParameters?: boolean }) {
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [newOrgName, setNewOrgName] = useState('');
    const [creating, setCreating] = useState(false);
    const { user, loading: authLoading } = useAuth();
    const [org, setOrg] = useState<Organization | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (authLoading) return;
        if (user?.organization_id) {
            fetchOrg(user.organization_id);
        } else {
            setLoading(false);
        }
    }, [user, authLoading]);

    async function fetchOrg(orgId: string) {
        try {
            const { data, error } = await supabase.from('organizations').select('*').eq('id', orgId).single();
            if (!error && data) setOrg(data);
        } catch (err) {
            console.error('Error fetching org:', err);
        } finally {
            setLoading(false);
        }
    }

    async function handleCreateOrg(e: React.FormEvent) {
        e.preventDefault();
        if (!newOrgName.trim()) return;
        setCreating(true);
        try {
            const newOrgId = crypto.randomUUID();
            const { error: orgError } = await supabase.from('organizations').insert({ id: newOrgId, name: newOrgName, plan: 'free' });
            if (orgError) throw orgError;
            const { error: memberError } = await supabase.from('organization_members').insert({ organization_id: newOrgId, user_id: user?.id, role: 'admin' });
            if (memberError) throw memberError;
            if (user) {
                await supabase.from('profiles').update({ organization_id: newOrgId }).eq('id', user.id);
                window.location.reload();
            }
        } catch (err: any) {
            alert("Error: " + err.message);
        } finally {
            setCreating(false);
        }
    }

    async function updateParameter(oldKey: string, newKey: string, newValue: string) {
        if (!org) return;
        const newSettings = { ...org.settings };
        if (oldKey !== newKey) {
            delete newSettings[oldKey];
        }
        newSettings[newKey] = newValue;
        const { error } = await supabase.from('organizations').update({ settings: newSettings }).eq('id', org.id);
        if (!error) setOrg({ ...org, settings: newSettings });
    }

    if (loading) return (
        <div className="flex flex-col items-center justify-center py-20">
            <div className="w-10 h-10 border-4 border-blue-600/20 border-t-blue-600 rounded-full animate-spin mb-4" />
            <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Sincronizando...</p>
        </div>
    );

    if (!org) return (
        <div className="flex flex-col items-center justify-center min-h-[400px] text-center p-8 space-y-6">
            <div className="w-20 h-20 bg-slate-50 dark:bg-slate-900 rounded-3xl flex items-center justify-center">
                <Building2 className="w-10 h-10 text-slate-300 dark:text-slate-700" />
            </div>
            <div>
                <h3 className="text-xl font-bold text-slate-900 dark:text-white uppercase tracking-tight">Sin Organizaci├│n</h3>
                <p className="text-slate-500 max-w-sm mx-auto mt-2 text-sm">Crea una organizaci├│n para comenzar.</p>
            </div>
            <button onClick={() => setShowCreateModal(true)} className="bg-slate-900 dark:bg-white dark:text-slate-900 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">
                Configurar Empresa
            </button>
            {showCreateModal && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/60 backdrop-blur-md">
                    <div className="bg-white dark:bg-slate-900 rounded-[2rem] w-full max-w-md p-10 border border-slate-100 dark:border-slate-800">
                        <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter mb-8">Nueva Empresa</h3>
                        <form onSubmit={handleCreateOrg} className="space-y-6">
                            <input
                                type="text"
                                required
                                value={newOrgName}
                                onChange={e => setNewOrgName(e.target.value)}
                                className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-slate-100 dark:border-slate-800 rounded-2xl focus:outline-none focus:border-blue-500 transition-all font-bold text-slate-900 dark:text-white"
                                placeholder="Nombre de la empresa"
                            />
                            <div className="flex gap-4">
                                <button type="button" onClick={() => setShowCreateModal(false)} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-black uppercase text-[10px] tracking-widest rounded-2xl">Volver</button>
                                <button type="submit" disabled={creating} className="flex-[2] py-4 bg-blue-600 text-white font-black uppercase text-[10px] tracking-widest rounded-2xl shadow-lg shadow-blue-500/20">
                                    {creating ? 'Creando...' : 'Confirmar'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );

    const parametersHeader = (
        <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 mb-10">
            <div>
                <div className="flex items-center gap-3 mb-2">
                    <div className="p-2 bg-blue-600 rounded-lg">
                        <Settings className="w-5 h-5 text-white" />
                    </div>
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Matriz de Par├ímetros</h3>
                </div>
                <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest pl-1">Variables de entorno globales para automatizaci├│n.</p>
            </div>
            <button
                onClick={async () => {
                    const key = prompt("Asigne un nombre (ID) al par├ímetro:");
                    if (key) {
                        const cleanKey = key.toUpperCase().replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '');
                        await updateParameter(cleanKey, cleanKey, 'Sin valor');
                    }
                }}
                className="bg-slate-900 dark:bg-blue-600 text-white px-6 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl flex items-center gap-3"
            >
                <Plus className="w-4 h-4" />
                Nueva Entrada
            </button>
        </div>
    );

    const parametersGrid = (
        <div className="overflow-hidden bg-white dark:bg-slate-900/50 rounded-[2rem] border border-slate-100 dark:border-slate-800">
            <table className="w-full text-left border-collapse">
                <thead>
                    <tr className="bg-slate-50/50 dark:bg-slate-950/50">
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificador (Key)</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor de Configuraci├│n</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right w-20">Acciones</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                    {Object.entries(org.settings || {}).length === 0 ? (
                        <tr>
                            <td colSpan={3} className="px-8 py-20 text-center">
                                <Package className="w-12 h-12 text-slate-200 dark:text-slate-800 mx-auto mb-4" />
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">No hay datos registrados</p>
                            </td>
                        </tr>
                    ) : (
                        Object.entries(org.settings || {}).map(([key, value]) => (
                            <tr key={key} className="group/row hover:bg-slate-50/50 dark:hover:bg-slate-950/30 transition-colors">
                                <td className="px-8 py-4">
                                    <div className="flex items-center gap-2">
                                        <input
                                            type="text"
                                            defaultValue={key}
                                            onBlur={(e) => {
                                                const newKey = e.target.value.toUpperCase().replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '');
                                                if (newKey && newKey !== key) updateParameter(key, newKey, value);
                                            }}
                                            className="bg-slate-50/50 dark:bg-slate-800/20 hover:bg-white dark:hover:bg-slate-800 border border-slate-100 dark:border-slate-800 px-3 py-1.5 rounded-lg text-xs font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none w-full transition-all"
                                        />
                                    </div>
                                </td>
                                <td className="px-8 py-4">
                                    <input
                                        type="text"
                                        defaultValue={value}
                                        onBlur={(e) => updateParameter(key, key, e.target.value)}
                                        className="bg-slate-50/50 dark:bg-slate-800/20 hover:bg-white dark:hover:bg-slate-800 border border-slate-100 dark:border-slate-800 px-3 py-1.5 rounded-lg text-xs font-bold text-slate-600 dark:text-slate-300 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none w-full transition-all"
                                        placeholder="Ingrese valor..."
                                    />
                                </td>
                                <td className="px-8 py-4 text-right">
                                    <button
                                        onClick={async () => {
                                            if (confirm(`┬┐Eliminar ${key}?`)) {
                                                const updatedSettings = { ...org.settings };
                                                delete updatedSettings[key];
                                                const { error } = await supabase.from('organizations').update({ settings: updatedSettings }).eq('id', org.id);
                                                if (!error) setOrg({ ...org, settings: updatedSettings });
                                            }
                                        }}
                                        className="p-2 text-slate-300 hover:text-rose-500 transition-all opacity-0 group-row:opacity-100 group-hover/row:opacity-100"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </td>
                            </tr>
                        ))
                    )}
                </tbody>
            </table>
        </div>
    );

    if (onlyParameters) {
        return (
            <div className="space-y-6 animate-in fade-in duration-500">
                <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm p-10 group/params">
                    {parametersHeader}
                    {parametersGrid}
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-in fade-in duration-500 relative">
            {/* Unified Action Bar */}
            <header className="flex flex-col lg:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900/50 p-2 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all duration-300">
                <div className="flex-1" />

                <div className="flex items-center gap-3">
                    <button
                        onClick={() => setShowCreateModal(true)}
                        className="bg-slate-900 dark:bg-blue-600 text-white px-4 py-2 rounded-xl text-[10px] font-black hover:bg-slate-800 dark:hover:bg-blue-700 transition-all shadow-lg shadow-blue-200 dark:shadow-none uppercase tracking-wider flex items-center gap-2"
                    >
                        <Plus className="w-3.5 h-3.5" />
                        Nueva Empresa
                    </button>
                </div>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 space-y-6">
                    {/* Organization Details */}
                    <div className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm p-8">
                        <div className="flex items-start justify-between mb-8">
                            <div>
                                <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Detalles de la Empresa</h3>
                                <p className="text-sm text-slate-400 font-medium">Informaci├│n general e identificadores ├║nicos.</p>
                            </div>
                            <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-2xl">
                                <Building2 className="w-6 h-6 text-slate-400" />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div className="space-y-6">
                                <div>
                                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Nombre Legal</label>
                                    <div className="flex items-center gap-3">
                                        <div className="text-2xl font-black text-slate-900 dark:text-white leading-tight">{org.name}</div>
                                        {user?.role === 'admin' && (
                                            <button
                                                onClick={() => {
                                                    const newName = prompt("Nuevo nombre de la empresa:", org.name);
                                                    if (newName && newName !== org.name) {
                                                        supabase.from('organizations').update({ name: newName }).eq('id', org.id)
                                                            .then(({ error }) => {
                                                                if (error) alert("Error al actualizar");
                                                                else {
                                                                    setOrg({ ...org, name: newName });
                                                                }
                                                            });
                                                    }
                                                }}
                                                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-blue-600 transition-colors"
                                            >
                                                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="w-4 h-4"><path d="M17 3a2.85 2.85 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z" /><path d="m15 5 4 4" /></svg>
                                            </button>
                                        )}
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">ID de Organizaci├│n</label>
                                    <div className="text-xs font-mono bg-slate-50 dark:bg-slate-950 px-4 py-3 rounded-xl border border-slate-100 dark:border-slate-800 text-slate-500 select-all tracking-tighter">
                                        {org.id}
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-6 bg-blue-50/30 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-50 dark:border-blue-900/20">
                                <div className="flex items-center gap-3 mb-2">
                                    <Shield className="w-5 h-5 text-blue-600" />
                                    <span className="text-[10px] font-black text-blue-900 dark:text-blue-100 uppercase tracking-widest">Seguridad y Auditor├¡a</span>
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1">Fecha de Creaci├│n</label>
                                    <div className="text-sm font-bold text-slate-700 dark:text-slate-300">
                                        {new Date(org.created_at).toLocaleDateString(undefined, { dateStyle: 'long' })}
                                    </div>
                                </div>
                                <div className="pt-2">
                                    <div className="text-[10px] text-blue-600/70 font-bold italic leading-relaxed">
                                        Esta organizaci├│n est├í protegida por cifrado de extremo a extremo y aislamiento multi-tenant.
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Company Parameters */}
                    <div className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-sm p-8 group/params">
                        <div className="flex items-start justify-between mb-8">
                            <div>
                                <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Par├ímetros Globales</h3>
                                <p className="text-sm text-slate-400 font-medium">Configura variables y constantes para tus flujos de trabajo.</p>
                            </div>
                            <button
                                onClick={async () => {
                                    const key = prompt("Nombre del par├ímetro (ej: ERP_URL, API_TOKEN):");
                                    if (key) {
                                        const cleanKey = key.toUpperCase().replace(/\s+/g, '_');
                                        const value = prompt(`Valor para ${cleanKey}:`);
                                        if (value !== null) {
                                            const updatedSettings = { ...(org.settings || {}), [cleanKey]: value };
                                            const { error } = await supabase.from('organizations').update({ settings: updatedSettings }).eq('id', org.id);
                                            if (error) alert("Error al guardar: " + error.message);
                                            else setOrg({ ...org, settings: updatedSettings });
                                        }
                                    }
                                }}
                                className="bg-blue-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:scale-105 transition-all shadow-lg shadow-blue-200 dark:shadow-none flex items-center gap-2"
                            >
                                <Plus className="w-4 h-4" />
                                A├▒adir Par├ímetro
                            </button>
                        </div>

                        <div className="space-y-4">
                            {Object.entries(org.settings || {}).length === 0 ? (
                                <div className="py-12 border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-3xl flex flex-col items-center justify-center text-center">
                                    <Settings className="w-10 h-10 text-slate-200 dark:text-slate-800 mb-4" />
                                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest leading-loose">No hay par├ímetros personalizados<br /><span className="text-[10px] text-slate-300">Usa el bot├│n superior para agregar el primero</span></p>
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {Object.entries(org.settings || {}).map(([key, value]) => (
                                        <div key={key} className="flex flex-col p-4 bg-slate-50 dark:bg-slate-950 rounded-2xl border border-slate-100 dark:border-slate-800 group/item relative hover:border-blue-200 transition-all">
                                            <div className="flex items-center justify-between mb-2">
                                                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{key}</span>
                                                <button
                                                    onClick={async () => {
                                                        if (confirm(`┬┐Eliminar par├ímetro ${key}?`)) {
                                                            const updatedSettings = { ...org.settings };
                                                            delete updatedSettings[key];
                                                            const { error } = await supabase.from('organizations').update({ settings: updatedSettings }).eq('id', org.id);
                                                            if (error) alert("Error al eliminar");
                                                            else setOrg({ ...org, settings: updatedSettings });
                                                        }
                                                    }}
                                                    className="p-1.5 text-slate-300 hover:text-rose-500 opacity-0 group-hover/item:opacity-100 transition-all"
                                                >
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </button>
                                            </div>
                                            <div className="flex gap-2">
                                                <input
                                                    type="text"
                                                    value={value}
                                                    onChange={async (e) => {
                                                        const newVal = e.target.value;
                                                        // Optimistic update
                                                        setOrg({ ...org, settings: { ...org.settings, [key]: newVal } });
                                                    }}
                                                    onBlur={async (e) => {
                                                        const updatedSettings = { ...org.settings, [key]: e.target.value };
                                                        await supabase.from('organizations').update({ settings: updatedSettings }).eq('id', org.id);
                                                    }}
                                                    className="w-full bg-transparent border-none p-0 text-sm font-bold text-slate-900 dark:text-white focus:ring-0 placeholder:text-slate-300"
                                                    placeholder="Valor del par├ímetro..."
                                                />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Plan Info & Sidebar */}
                <div className="space-y-6">
                    <div className="bg-slate-900 dark:bg-blue-600 text-white rounded-[2rem] shadow-xl shadow-slate-200 dark:shadow-none p-8 relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full blur-3xl -mr-16 -mt-16"></div>

                        <div className="relative z-10">
                            <div className="flex items-center gap-2 mb-2 text-blue-300">
                                <CreditCard className="w-5 h-5" />
                                <span className="text-[10px] font-black uppercase tracking-widest opacity-70">Plan de Servicio</span>
                            </div>
                            <h3 className="text-4xl font-black mb-8 capitalize">{org.plan}</h3>

                            <div className="space-y-4 mb-10">
                                <FeatureItem text="Usuarios Ilimitados" active={true} />
                                <FeatureItem text="Flujos Ilimitados" active={true} />
                                <FeatureItem text="Soporte Prioritario" active={org.plan === 'enterprise'} />
                                <FeatureItem text="API Access Global" active={org.plan !== 'free'} />
                                <FeatureItem text="Copia de Seguridad" active={true} />
                            </div>

                            <button className="w-full py-4 bg-white text-slate-900 font-black text-xs uppercase tracking-widest rounded-2xl hover:bg-blue-50 transition-all active:scale-95 shadow-lg">
                                Gestionar Suscripci├│n
                            </button>
                        </div>
                    </div>

                    <div className="bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-100 dark:border-slate-800 p-8">
                        <div className="flex items-center gap-3 mb-4">
                            <Users className="w-5 h-5 text-blue-600" />
                            <h3 className="text-lg font-bold text-slate-900 dark:text-white">Equipo</h3>
                        </div>
                        <p className="text-xs text-slate-500 font-medium leading-relaxed mb-6">
                            Est├ís operando con el rol de <strong className="text-slate-900 dark:text-slate-200 underline decoration-blue-500/30">{user?.role === 'admin' ? 'Administrador' : 'Miembro'}</strong>.
                            {user?.role === 'admin'
                                ? ' Tienes control total sobre los par├ímetros y miembros de la organizaci├│n.'
                                : ' Contacta a tu administrador para solicitar acceso a par├ímetros globales.'}
                        </p>
                        <div className="pt-4 border-t border-slate-50 dark:border-slate-800 flex justify-center">
                            <button className="text-[10px] font-black text-blue-600 uppercase tracking-widest hover:text-blue-700 transition-colors">
                                Ver todos los miembros ÔåÆ
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function FeatureItem({ text, active }: { text: string, active: boolean }) {
    return (
        <div className={`flex items-center gap-3 ${active ? 'text-white' : 'text-slate-500 opacity-50'}`}>
            <CheckCircle2 className="w-4 h-4" />
            <span className="text-sm font-medium">{text}</span>
        </div>
    );
}

import { useState } from 'react';
import { useOrgChart } from '../hooks/useOrgChart';
import {
    Users,
    ChevronRight,
    ChevronDown,
    Plus,
    Trash2,
    DollarSign,
    Settings,
    Network,
    Briefcase,
    PlusCircle,
    Building2,
    Shield,
    UserCircle,
    UserPlus,
    Clock,
    X as CloseIcon,
    LayoutDashboard,
    RefreshCw,
    ZoomIn,
    ZoomOut,
    Maximize
} from 'lucide-react';
import { cn } from '../utils/cn';
import { GraphicalTreeView } from './OrgChartTree';
import type { DepartmentWithChildren } from '../types';

interface OrganizationalChartProps {
    organizationId: string;
}

export function OrganizationalChart({ organizationId }: OrganizationalChartProps) {
    const {
        tree,
        departments,
        positions,
        availableCollaborators,
        loading,
        saveDepartment,
        deleteDepartment,
        savePosition,
        deletePosition,
        assignEmployee,
        removeEmployee,
        reload
    } = useOrgChart(organizationId);

    const [selectedDeptId, setSelectedDeptId] = useState<string | null>(null);
    const [isAddingDept, setIsAddingDept] = useState<{ parentId: string | null }>({ parentId: null });
    const [newDeptName, setNewDeptName] = useState('');
    const [assigningToPosition, setAssigningToPosition] = useState<string | null>(null);
    const [viewMode, setViewMode] = useState<'list' | 'graphical'>('graphical');
    const [zoom, setZoom] = useState(1);
    const [offset, setOffset] = useState({ x: 0, y: 0 });

    const selectedDept = departments.find(d => d.id === selectedDeptId);

    if (loading) {
        return (
            <div className="flex items-center justify-center p-12">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    return (
        <div className="flex h-[calc(100vh-110px)] gap-4 animate-in fade-in duration-500">
            {/* Tree View / Graphical View */}
            <div className="flex-1 bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-200 dark:border-slate-800 p-5 overflow-hidden flex flex-col shadow-sm relative">


                <div className="flex-1 overflow-auto custom-scrollbar pr-2 h-full">
                    {viewMode === 'list' ? (
                        <div className="space-y-4 pt-4">
                            {tree.map(dept => (
                                <DeptNode
                                    key={dept.id}
                                    dept={dept}
                                    onSelect={setSelectedDeptId}
                                    selectedId={selectedDeptId}
                                    onAddChild={(parentId: string) => setIsAddingDept({ parentId })}
                                />
                            ))}
                        </div>
                    ) : (
                        <GraphicalTreeView
                            tree={tree}
                            onSelect={setSelectedDeptId}
                            selectedId={selectedDeptId}
                            onAddChild={(parentId: string) => setIsAddingDept({ parentId })}
                            zoom={zoom}
                            setZoom={setZoom}
                            offset={offset}
                            setOffset={setOffset}
                        />
                    )}
                </div>

                {/* Floating Unified Action Bar */}
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md p-1.5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-2xl z-50">
                    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                        <button
                            onClick={() => setViewMode('graphical')}
                            className={cn(
                                "px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-2",
                                viewMode === 'graphical' ? "bg-white dark:bg-slate-700 text-blue-600 shadow-sm" : "text-slate-400 hover:text-slate-600"
                            )}
                        >
                            <Network className="w-3.5 h-3.5" />
                            ├ürbol
                        </button>
                        <button
                            onClick={() => setViewMode('list')}
                            className={cn(
                                "px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-2",
                                viewMode === 'list' ? "bg-white dark:bg-slate-700 text-blue-600 shadow-sm" : "text-slate-400 hover:text-slate-600"
                            )}
                        >
                            <LayoutDashboard className="w-3.5 h-3.5" />
                            Lista
                        </button>
                    </div>

                    <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1" />

                    <button
                        onClick={() => (reload as any)(true)}
                        className="p-2 bg-slate-100 dark:bg-slate-800 text-slate-500 hover:text-blue-600 rounded-xl transition-all"
                        title="Refrescar Carga"
                    >
                        <RefreshCw className={cn("w-3.5 h-3.5", loading && "animate-spin")} />
                    </button>

                    {departments.length === 0 && (
                        <>
                            <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1" />
                            <button
                                onClick={() => saveDepartment({ name: 'Direcci├│n General' })}
                                className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700"
                                title="Crear Nodo Ra├¡z"
                            >
                                <Plus className="w-3.5 h-3.5" />
                            </button>
                        </>
                    )}

                    {viewMode === 'graphical' && (
                        <>
                            <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1" />
                            <div className="flex items-center gap-1">
                                <button onClick={() => setZoom(z => Math.min(z * 1.2, 2))} className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-slate-500 transition-all"><ZoomIn className="w-3.5 h-3.5" /></button>
                                <span className="text-[9px] font-black w-8 text-center text-slate-400">{Math.round(zoom * 100)}%</span>
                                <button onClick={() => setZoom(z => Math.max(z / 1.2, 0.4))} className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-slate-500 transition-all"><ZoomOut className="w-3.5 h-3.5" /></button>
                                <div className="w-px h-4 bg-slate-200 dark:bg-slate-800 mx-0.5" />
                                <button onClick={() => { setZoom(1); setOffset({ x: 0, y: 0 }); }} className="p-1.5 hover:bg-blue-50 dark:hover:bg-blue-900/40 text-blue-600 rounded-lg transition-all" title="Centrar"><Maximize className="w-3.5 h-3.5" /></button>
                            </div>
                        </>
                    )}
                </div>
            </div>

            {/* Rules and Details Panel */}
            <div className="w-[320px] bg-white dark:bg-slate-900 rounded-[2rem] border border-slate-200 dark:border-slate-800 p-5 flex flex-col gap-5 overflow-y-auto shadow-sm custom-scrollbar">
                {selectedDept ? (
                    <>
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="p-2.5 bg-blue-600 rounded-xl shadow-lg shadow-blue-200 dark:shadow-none">
                                    <Building2 className="w-4 h-4 text-white" />
                                </div>
                                <div className="overflow-hidden">
                                    <h3 className="font-black text-slate-400 dark:text-slate-500 leading-tight uppercase text-[9px] tracking-widest truncate">├ürea Seleccionada</h3>
                                    <div className="flex items-center gap-2">
                                        <p className="text-base font-bold text-blue-600 dark:text-blue-400 truncate max-w-[150px]">{selectedDept.name}</p>
                                        {positions.filter(p => p.department_id === selectedDept.id).reduce((acc, p) => acc + ((p as any).workload_count || 0), 0) > 0 && (
                                            <span className="px-2 py-0.5 bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 text-[10px] font-black rounded-lg">
                                                {positions.filter(p => p.department_id === selectedDept.id).reduce((acc, p) => acc + ((p as any).workload_count || 0), 0)} PENDIENTES
                                            </span>
                                        )}
                                    </div>
                                </div>
                            </div>
                            <button
                                onClick={() => {
                                    if (confirm('┬┐Seguro que quieres eliminar esta ├írea y todas sus sub├íreas?')) {
                                        deleteDepartment(selectedDept.id);
                                        setSelectedDeptId(null);
                                    }
                                }}
                                className="p-2 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-all"
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>

                        {/* Cargos y Equipo */}
                        <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                            <div className="flex items-center justify-between">
                                <h4 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                                    <Briefcase className="w-3 h-3" />
                                    Cargos y Equipo
                                </h4>
                                <button
                                    onClick={() => {
                                        const title = prompt('Nombre del cargo:');
                                        if (title) savePosition({ title, department_id: selectedDept.id });
                                    }}
                                    className="p-1.5 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-100 transition-all shadow-sm"
                                >
                                    <Plus className="w-3.5 h-3.5" />
                                </button>
                            </div>

                            <div className="space-y-3">
                                {positions.filter(p => p.department_id === selectedDept.id).map(pos => (
                                    <div key={pos.id} className="p-3 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-800 group transition-all space-y-3">
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-lg bg-white dark:bg-slate-900 flex items-center justify-center shadow-sm">
                                                    <Shield className="w-4 h-4 text-blue-500" />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-xs font-black text-slate-800 dark:text-slate-200">{pos.title}</span>
                                                    {(pos as any).workload_count > 0 && (
                                                        <span className="text-[8px] font-black text-blue-500 uppercase">{(pos as any).workload_count} tr├ímites</span>
                                                    )}
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-1">
                                                {(pos as any).workload_count > 0 && (
                                                    <span className="flex items-center gap-0.5 px-1.5 py-0.5 bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-300 text-[9px] font-black rounded-md border border-blue-200 dark:border-blue-800">
                                                        <Clock className="w-2.5 h-2.5" />
                                                        {(pos as any).workload_count}
                                                    </span>
                                                )}
                                                <button
                                                    onClick={() => setAssigningToPosition(pos.id)}
                                                    className="p-1.5 text-blue-600 hover:bg-blue-100 dark:hover:bg-blue-900/40 rounded-lg transition-all"
                                                >
                                                    <UserPlus className="w-3.5 h-3.5" />
                                                </button>
                                                <button
                                                    onClick={() => { if (confirm('┬┐Eliminar cargo?')) deletePosition(pos.id) }}
                                                    className="p-1.5 text-slate-300 hover:text-rose-500 transition-all"
                                                >
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </button>
                                            </div>
