                            <button
                                onClick={() => {
                                    if (newDeptName) {
                                        saveDepartment({ name: newDeptName, parent_department_id: isAddingDept.parentId || undefined });
                                        setIsAddingDept({ parentId: null });
                                        setNewDeptName('');
