                    >
                        <Download className="w-3 h-3" />
                        Exportar
                    </button>
                </div>
            </div>

            {/* Operation Report Content */}
            {
                activeTab === 'operation' && (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 animate-in slide-in-from-bottom-5 duration-500">
                        {/* Global Process Efficiency Dashboard */}
