            if (!user) return;

            const { data: profile } = await supabase
                .from('profiles')
                .select('organization_id')
                .eq('id', user.id)
                .single();

            const orgId = profile?.organization_id;
            if (!orgId) {
                alert('No tienes una organizaci├│n activa.');
                return;
            }

            setLoading(true);
            const { error: memberError } = await supabase
                .from('organization_members')
                .insert({
                    organization_id: orgId,
                    user_id: accountId,
                    role: 'viewer'
                });

            if (memberError) {
                if (memberError.code === '23505') throw new Error('El usuario ya pertenece a esta organizaci├│n.');
                throw memberError;
            }

            alert(`Usuario ${email} vinculado correctamente a tu empresa.`);
            fetchAccounts();
