import { useState, useEffect, useCallback } from 'react';
import { supabase } from '../lib/supabase';
import { useAuth } from './useAuth';

export function useDashboardStats() {
    const { user } = useAuth();
    const [stats, setStats] = useState({
        workflows: 0,
        activities: 0,
        transitions: 0,
        users: 0,
        instancesActive: 0,
        instancesCompleted: 0,
        historyCount: 0,
        loading: true
    });

    const fetchStats = useCallback(async () => {
        try {
            const orgId = user?.organization_id;
            const userId = user?.id;
            if (!orgId || !userId) return;

            // Build base queries - Personalized for the user
            const qWorkflows = supabase.from('workflows').select('*', { count: 'exact', head: true }).eq('organization_id', orgId);
            const qActivities = supabase.from('activities').select('*', { count: 'exact', head: true }).eq('organization_id', orgId);
            const qTransitions = supabase.from('transitions').select('*', { count: 'exact', head: true });
            const qUsers = supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('organization_id', orgId);

            // Filter instances by current user
            const qActive = supabase.from('process_instances')
                .select('*', { count: 'exact', head: true })
                .eq('status', 'active')
                .eq('organization_id', orgId)
                .eq('created_by', userId);

            const qCompleted = supabase.from('process_instances')
                .select('*', { count: 'exact', head: true })
                .eq('status', 'completed')
                .eq('organization_id', orgId)
                .eq('created_by', userId);

            const qHistory = supabase.from('process_history')
                .select('*', { count: 'exact', head: true })
                .eq('user_id', userId);

            const [workflows, activities, transitions, users, instancesActive, instancesCompleted, history] = await Promise.all([
                qWorkflows,
                qActivities,
                qTransitions,
                qUsers,
                qActive,
                qCompleted,
                qHistory
            ]);

            setStats({
                workflows: workflows.count || 0,
                activities: activities.count || 0,
                transitions: transitions.count || 0,
                users: users.count || 0,
                instancesActive: instancesActive.count || 0,
                instancesCompleted: instancesCompleted.count || 0,
                historyCount: history.count || 0,
                loading: false
            });
        } catch (error) {
            console.error('Error fetching dashboard stats:', error);
            setStats(prev => ({ ...prev, loading: false }));
        }
    }, [user?.organization_id, user?.id]);

    useEffect(() => {
        if (user?.organization_id) {
            fetchStats();

            // Set up real-time subscriptions
            const channels = [
                supabase.channel('public:workflows').on('postgres_changes', { event: '*', schema: 'public', table: 'workflows' }, fetchStats).subscribe(),
                supabase.channel('public:activities').on('postgres_changes', { event: '*', schema: 'public', table: 'activities' }, fetchStats).subscribe(),
                supabase.channel('public:transitions').on('postgres_changes', { event: '*', schema: 'public', table: 'transitions' }, fetchStats).subscribe(),
                supabase.channel('public:profiles').on('postgres_changes', { event: '*', schema: 'public', table: 'profiles' }, fetchStats).subscribe(),
                supabase.channel('public:process_instances').on('postgres_changes', { event: '*', schema: 'public', table: 'process_instances' }, fetchStats).subscribe(),
                supabase.channel('public:process_history').on('postgres_changes', { event: '*', schema: 'public', table: 'process_history' }, fetchStats).subscribe()
            ];

            return () => {
                channels.forEach(channel => supabase.removeChannel(channel));
            };
        }
    }, [user?.organization_id, fetchStats]);

    return { ...stats, refresh: fetchStats };
}

import { useState } from 'react';
import { supabase } from '../lib/supabase';

import { useAuth } from './useAuth';
import { executeServiceTask } from '../utils/actionRunner';

export function useExecution() {
    const { user } = useAuth();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Fetch active tasks for the current user (Inbox)
    async function getActiveTasks() {
        try {
            setLoading(true);

            // 1. Get current user's positions and departments
            const { data: userPos } = await supabase
                .from('employee_positions')
                .select(`
                    position_id,
                    positions (department_id)
                `)
                .eq('user_id', user?.id);

            const positionIds = userPos?.map(p => p.position_id) || [];
            const departmentIds = userPos?.map(p => (p.positions as any)?.department_id).filter(Boolean) || [];

            // 2. Fetch tasks matching user, position, department or truly public (all null)
            let filter = `assigned_user_id.eq.${user?.id}`;

            // Truly public tasks (no user, no dept, no position)
            filter += `,and(assigned_user_id.is.null,assigned_department_id.is.null,assigned_position_id.is.null)`;

            if (positionIds.length > 0) {
                filter += `,assigned_position_id.in.(${positionIds.map(id => `"${id}"`).join(',')})`;
            }
            if (departmentIds.length > 0) {
                filter += `,assigned_department_id.in.(${departmentIds.map(id => `"${id}"`).join(',')})`;
            }

            const { data, error } = await supabase
                .from('process_instances')
                .select(`
                    *,
                    workflows (name, description),
                    activities (*)
                `)
                .eq('status', 'active')
                .or(filter)
                .order('created_at', { ascending: false });

            if (error) throw error;
            return data;
        } catch (err: any) {
            setError(err.message);
            return [];
        } finally {
            setLoading(false);
        }
    }

    // Start a new process instance
    async function startProcess(workflowId: string, name: string, organizationId: string) {
        try {
            setLoading(true);

            // 1. Get the start activity for this workflow
            const { data: activities, error: actError } = await supabase
                .from('activities')
                .select('*')
                .eq('workflow_id', workflowId)
                .eq('type', 'start')
                .single();

            if (actError) throw new Error('No se encontr├│ el nodo de inicio para este flujo.');

            // 2. Create the process instance
            const { data: instance, error: insError } = await supabase
                .from('process_instances')
                .insert({
                    workflow_id: workflowId,
                    name: name,
                    organization_id: organizationId,
                    current_activity_id: activities.id,
                    status: 'active',
                    assigned_user_id: user?.id // Default creator
                })
                .select()
                .single();

            if (insError) throw insError;

            // 3. Record initial history
            const { error: histError } = await supabase
                .from('process_history')
                .insert({
                    process_id: instance.id,
                    activity_id: activities.id,
                    action: 'started',
                    comment: 'Tr├ímite iniciado autom├íticamente.',
                    user_id: user?.id
                });

            if (histError) throw histError;

            return { success: true, instance };
        } catch (err: any) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    }

    async function advanceProcess(processId: string, transitionId: string, comment?: string) {
        try {
            setLoading(true);

            // 1. Get transition details
            const { data: transition, error: transError } = await supabase
                .from('transitions')
                .select('target_id')
                .eq('id', transitionId)
                .single();

            if (transError) throw transError;

            // 1.5 Calculate next assignment
            const { data: targetActivity } = await supabase
                .from('activities')
                .select('*')
                .eq('id', transition.target_id)
                .single();

            // Get original initiator for 'creator' rule
            const { data: instance } = await supabase
                .from('process_instances')
                .select('created_by, organization_id')
                .eq('id', processId)
                .single();

            let nextAssignment: any = { assigned_user_id: null, assigned_department_id: null, assigned_position_id: null };
            if (targetActivity) {
                nextAssignment = await calculateAssignment(targetActivity, instance?.created_by || user?.id || '', instance?.organization_id);
            }

            // 2. Update process instance to next activity
            const { error: updError } = await supabase
                .from('process_instances')
                .update({
                    current_activity_id: transition.target_id,
                    status: 'active',
                    ...nextAssignment
                })
                .eq('id', processId);

            if (updError) throw updError;

            // 3. Record history
            const { error: histError } = await supabase
                .from('process_history')
                .insert({
                    process_id: processId,
                    activity_id: transition.target_id,
                    action: 'completed',
                    comment: comment || 'Actividad completada.',
                    user_id: user?.id
                });

            if (histError) throw histError;

            // 4. Trigger Automatic Actions if configured
            if (targetActivity && targetActivity.action_type && targetActivity.action_type !== 'none') {
                try {
                    const { data: allData } = await supabase.from('process_data').select('field_name, value').eq('process_id', processId);
                    const context: Record<string, any> = { process_id: processId, user_id: user?.id };
                    allData?.forEach(d => context[d.field_name] = d.value);

                    const steps = (targetActivity.action_config as any)?.steps || [{ id: '1', ...targetActivity.action_config }];

                    // Fetch organization settings for parameter substitution
                    const { data: orgData } = await supabase
                        .from('organizations')
                        .select('settings')
                        .eq('id', instance?.organization_id)
                        .single();

                    const actionResult = await executeServiceTask(steps as any, context, orgData?.settings || {});

                    if (!actionResult.success) {
                        await supabase.from('process_history').insert({
                            process_id: processId,
                            activity_id: transition.target_id,
                            action: 'commented',
                            comment: `ÔØî Error en Acci├│n Autom├ítica: ${actionResult.error}`,
                            user_id: user?.id
                        });
                    } else {
                        const outputsToSave = Object.entries(actionResult.outputs)
                            .filter(([key]) => key !== 'process_id' && key !== 'user_id' && !context[key])
                            .map(([name, value]) => ({
                                process_id: processId,
                                activity_id: transition.target_id,
                                field_name: name,
                                value: typeof value === 'object' ? JSON.stringify(value) : String(value)
                            }));

                        if (outputsToSave.length > 0) await supabase.from('process_data').insert(outputsToSave);

                        await supabase.from('process_history').insert({
                            process_id: processId,
                            activity_id: transition.target_id,
                            action: 'commented',
                            comment: `Ô£à Acciones Autom├íticas ejecutadas con ├®xito. (${steps.length} pasos)`,
                            user_id: user?.id
                        });
                    }
                } catch (actionErr: any) {
                    console.error('Action Execution Failed:', actionErr);
                }
            }

            return { success: true };
        } catch (err: any) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    }

    async function getFieldDefinitions(activityId: string) {
        const { data, error } = await supabase
            .from('activity_field_definitions')
            .select('*')
            .eq('activity_id', activityId);
        if (error) throw error;
        return data;
    }

    async function getProcessData(processId: string, activityId: string) {
        const { data, error } = await supabase
            .from('process_data')
            .select('*')
            .eq('process_id', processId)
            .eq('activity_id', activityId);
        if (error) throw error;
        return data;
    }

    async function saveProcessData(processId: string, activityId: string, fields: Record<string, string>) {
        try {
            setLoading(true);
            // Delete existing data for this activity in this process to avoid duplicates
            await supabase
                .from('process_data')
                .delete()
                .eq('process_id', processId)
                .eq('activity_id', activityId);

            const dataToInsert = Object.entries(fields).map(([name, value]) => ({
                process_id: processId,
                activity_id: activityId,
                field_name: name,
                value: String(value)
            }));

            if (dataToInsert.length > 0) {
                const { error } = await supabase.from('process_data').insert(dataToInsert);
                if (error) throw error;
            }

            // --- RESOLVE DYNAMIC NAME LOGIC ---
            // 1. Get process instance and workflow info
            const { data: instance } = await supabase
                .from('process_instances')
                .select('*, workflows(name_template, name)')
                .eq('id', processId)
                .single();

            if (instance && instance.workflows?.name_template) {
                // 2. Check if this is the START activity
                const { data: startActivity } = await supabase
                    .from('activities')
                    .select('id')
                    .eq('workflow_id', instance.workflow_id)
                    .eq('type', 'start')
                    .single();

                if (activityId === startActivity?.id) {
                    let fullyResolved = true;
                    let newName = instance.workflows.name_template;

                    // Replace variables {{field_name}}
                    newName = newName.replace(/{{(.*?)}}/g, (match: string, fieldName: string) => {
                        const cleanName = fieldName.trim();
                        // 1. Try direct match
                        if (fields[cleanName] !== undefined && fields[cleanName] !== '') {
                            return fields[cleanName];
                        }
                        // 2. Try normalized match (lowercase, spaces to underscores)
                        const normalizedName = cleanName.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
                        if (fields[normalizedName] !== undefined && fields[normalizedName] !== '') {
                            return fields[normalizedName];
                        }

                        fullyResolved = false;
                        return match;
                    });

                    // Update instance name only if fully resolved and it actually changed
                    if (fullyResolved && newName !== instance.name) {
                        await supabase
                            .from('process_instances')
                            .update({ name: newName })
                            .eq('id', processId);
                    }
                }
            }
            // ----------------------------------

            return { success: true };
        } catch (err: any) {
            console.error('Error saving process data:', err);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    }

    async function completeProcess(processId: string, comment?: string) {
        try {
            setLoading(true);

            // 1. Verify instance exists
            const { data: instance, error: insError } = await supabase
                .from('process_instances')
                .select('*, activities(type)')
                .eq('id', processId)
                .single();

            if (insError) throw insError;

            // 2. Update process status
            const { error: updError } = await supabase
                .from('process_instances')
                .update({
                    status: 'completed'
                })
                .eq('id', processId);

            if (updError) throw updError;

            // 3. Record history
            const { error: histError } = await supabase
                .from('process_history')
                .insert({
                    process_id: processId,
                    activity_id: instance.current_activity_id,
                    action: 'completed',
                    comment: comment || 'Tr├ímite finalizado manualmente.',
                    user_id: user?.id
                });

            if (histError) throw histError;

            return { success: true };
        } catch (err: any) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    }

    async function calculateAssignment(activity: any, creatorId: string, orgId?: string) {
        // Initialize result with activity defaults (so it's assigned to group if no user strategy is set)
        const result = {
            assigned_user_id: null as string | null,
            assigned_department_id: activity.assigned_department_id || null,
            assigned_position_id: activity.assigned_position_id || null
        };

        if (!activity.assignment_type || activity.assignment_type === 'manual') {
            return result;
        }

        if (activity.assignment_type === 'creator') {
            result.assigned_user_id = creatorId;
            return result;
        }

        if (activity.assignment_type === 'specific_user') {
            result.assigned_user_id = activity.assigned_user_id || null;
            return result;
        }

        if (activity.assignment_type === 'department' || activity.assignment_type === 'position') {
            const strategy = activity.assignment_strategy || 'manual';

            // Find collaborators for the group
            let query = supabase.from('employee_positions').select('user_id');
            if (activity.assigned_position_id) {
                query = query.eq('position_id', activity.assigned_position_id);
            } else if (activity.assigned_department_id) {
                const { data: positions } = await supabase.from('positions').select('id').eq('department_id', activity.assigned_department_id);
                if (positions && positions.length > 0) {
                    query = query.in('position_id', positions.map(p => p.id));
                } else {
                    return result; // Fallback to group
                }
            }

            const { data: employees } = await query;
            const userIds = employees?.map(e => e.user_id).filter(Boolean) as string[] || [];

            if (userIds.length === 0) {
                return result; // Fallback to group
            }

            if (strategy === 'workload') {
                let workloadQuery = supabase.from('process_instances')
                    .select('assigned_user_id')
                    .eq('status', 'active')
                    .in('assigned_user_id', userIds);

                if (orgId) {
                    workloadQuery = workloadQuery.eq('organization_id', orgId);
                }

                const { data: workloads } = await workloadQuery;
                const counts: Record<string, number> = {};
                userIds.forEach(id => counts[id] = 0);
                workloads?.forEach(w => { if (w.assigned_user_id) counts[w.assigned_user_id]++; });

                result.assigned_user_id = userIds.reduce((a, b) => counts[a] <= counts[b] ? a : b);
                return result;
            }

            if (strategy === 'efficiency') {
                let historyQuery = supabase.from('process_history')
                    .select('user_id')
                    .eq('action', 'completed')
                    .in('user_id', userIds);

                const { data: history } = await historyQuery;
                const stats: Record<string, number> = {};
                userIds.forEach(id => stats[id] = 0);
                history?.forEach(h => { if (h.user_id) stats[h.user_id]++; });

                result.assigned_user_id = userIds.reduce((a, b) => stats[a] >= stats[b] ? a : b);
                return result;
            }

            if (strategy === 'random') {
                const randomIndex = Math.floor(Math.random() * userIds.length);
                result.assigned_user_id = userIds[randomIndex];
                return result;
            }
        }

        return result;
    }

    return {
        loading,
        error,
        getActiveTasks,
        startProcess,
        advanceProcess,
        getFieldDefinitions,
        getProcessData,
        saveProcessData,
        completeProcess,
        getBimStates: async (processId: string) => {
            const { data, error } = await supabase
                .from('process_bim_states')
                .select('*')
                .eq('process_id', processId);
            if (error) throw error;
            return data;
        },
        saveBimState: async (processId: string, expressId: number, status: string) => {
            const { error } = await supabase
                .from('process_bim_states')
                .upsert({
                    process_id: processId,
                    express_id: expressId,
                    status,
                    updated_at: new Date().toISOString(),
                    updated_by: user?.id
                });
            if (error) throw error;
            return { success: true };
        }
    };
}

import { useState } from 'react';
import { supabase } from '../lib/supabase';
import { useAuth } from './useAuth';

interface FileUploadResult {
    id: string;
    file_name: string;
    file_path: string;
    file_size: number;
    file_type: string;
}

export function useFileUpload() {
    const [uploading, setUploading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const { user } = useAuth();

    const uploadFile = async (file: File, processInstanceId: string): Promise<FileUploadResult | null> => {
        try {
            setUploading(true);
            setError(null);

            // Validate file size (10MB max)
            const maxSize = 10 * 1024 * 1024;
            if (file.size > maxSize) {
                throw new Error('El archivo no puede superar 10MB');
            }

            // Validate file type
            const fileExt = file.name.split('.').pop()?.toLowerCase() || '';
            const allowedExtensions = ['pdf', 'png', 'jpg', 'jpeg', 'docx', 'xlsx', 'ifc'];
            if (!allowedExtensions.includes(fileExt)) {
                throw new Error('Tipo de archivo no permitido. Solo PDF, im├ígenes, DOCX, XLSX e IFC');
            }

            // Generate unique file path
            const fileName = `${processInstanceId}/${Date.now()}.${fileExt}`;

            // Upload to Supabase Storage
            const { data: uploadData, error: uploadError } = await supabase.storage
                .from('process-files')
                .upload(fileName, file);

            if (uploadError) throw uploadError;

            // Create database record
            const { data: attachmentData, error: dbError } = await supabase
                .from('process_attachments')
                .insert({
                    process_instance_id: processInstanceId,
                    file_name: file.name,
                    file_path: uploadData.path,
                    file_size: file.size,
                    file_type: file.type,
                    uploaded_by: user?.id,
                    organization_id: user?.organization_id
                })
                .select()
                .single();

            if (dbError) throw dbError;

            return attachmentData;
        } catch (err: any) {
            setError(err.message);
            return null;
        } finally {
            setUploading(false);
        }
    };

    const deleteFile = async (attachmentId: string, filePath: string): Promise<boolean> => {
        try {
            setError(null);

            // Delete from storage
            const { error: storageError } = await supabase.storage
                .from('process-files')
                .remove([filePath]);

            if (storageError) throw storageError;

            // Delete from database
            const { error: dbError } = await supabase
                .from('process_attachments')
                .delete()
                .eq('id', attachmentId);

            if (dbError) throw dbError;

            return true;
        } catch (err: any) {
            setError(err.message);
            return false;
        }
    };

    const downloadFile = async (filePath: string, fileName: string) => {
        try {
            setError(null);

            // Get signed URL
            const { data, error } = await supabase.storage
                .from('process-files')
                .createSignedUrl(filePath, 60); // Valid for 60 seconds

            if (error) throw error;

            // Download file
            const link = document.createElement('a');
            link.href = data.signedUrl;
            link.download = fileName;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        } catch (err: any) {
            setError(err.message);
        }
    };

    return {
        uploadFile,
        deleteFile,
        downloadFile,
        uploading,
        error
    };
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import type { Department, Position, DepartmentWithChildren, EmployeePosition } from '../types';

export function useOrgChart(organizationId: string) {
    const [departments, setDepartments] = useState<Department[]>([]);
    const [positions, setPositions] = useState<Position[]>([]);
    const [employeePositions, setEmployeePositions] = useState<EmployeePosition[]>([]);
    const [availableCollaborators, setAvailableCollaborators] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!organizationId) return;

        loadChart(true);

        // Subscribe to changes in process_instances to update workload in real-time
        const channel = supabase.channel(`org_workload_${organizationId}`)
            .on('postgres_changes', {
                event: '*',
                schema: 'public',
                table: 'process_instances'
            }, (payload: any) => {
                // If the instance belongs to our org, refresh without showing full loader
                if (payload.new?.organization_id === organizationId || payload.old?.organization_id === organizationId) {
                    loadChart(false);
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [organizationId]);

    async function loadChart(showLoading = false) {
        try {
            if (showLoading) setLoading(true);
            // Fetch workload data for the organization
            const [deptRes, posRes, empPosRes, workloadRes] = await Promise.all([
                supabase.from('departments').select('*').eq('organization_id', organizationId).order('name'),
                supabase.from('positions').select('*').eq('organization_id', organizationId).order('level'),
                supabase.from('employee_positions')
                    .select('*, user:profiles(id, full_name, email)'),
                supabase.from('process_instances')
                    .select('assigned_user_id, assigned_position_id, assigned_department_id')
                    .eq('organization_id', organizationId)
                    .eq('status', 'active')
            ]);

            const userWorkload: Record<string, number> = {};
            const posWorkload: Record<string, number> = {};
            const deptWorkload: Record<string, number> = {};

            // Helper maps for rollups
            const posToDept: Record<string, string> = {};
            posRes.data?.forEach(p => { if (p.department_id) posToDept[p.id] = p.department_id; });

            const userToPositions: Record<string, string[]> = {};
            empPosRes.data?.forEach(ep => {
                if (!userToPositions[ep.user_id]) userToPositions[ep.user_id] = [];
                userToPositions[ep.user_id].push(ep.position_id);
            });

            workloadRes.data?.forEach(w => {
                // 1. Direct counts
                if (w.assigned_user_id) {
                    userWorkload[w.assigned_user_id] = (userWorkload[w.assigned_user_id] || 0) + 1;
                    // Roll up to user's positions and their departments
                    userToPositions[w.assigned_user_id]?.forEach(posId => {
                        posWorkload[posId] = (posWorkload[posId] || 0) + 1;
                        if (posToDept[posId]) deptWorkload[posToDept[posId]] = (deptWorkload[posToDept[posId]] || 0) + 1;
                    });
                } else if (w.assigned_position_id) {
                    posWorkload[w.assigned_position_id] = (posWorkload[w.assigned_position_id] || 0) + 1;
                    // Roll up to position's department
                    if (posToDept[w.assigned_position_id]) {
                        deptWorkload[posToDept[w.assigned_position_id]] = (deptWorkload[posToDept[w.assigned_position_id]] || 0) + 1;
                    }
                } else if (w.assigned_department_id) {
                    deptWorkload[w.assigned_department_id] = (deptWorkload[w.assigned_department_id] || 0) + 1;
                }
            });

            console.log('Workload data calculated');

            if (deptRes.error) throw deptRes.error;
            if (posRes.error) throw posRes.error;
            if (empPosRes.error) throw empPosRes.error;

            // Cargar colaboradores de la organizaci├│n para el dropdown de asignaci├│n
            const { data: collaborators } = await supabase
                .from('organization_members')
                .select('user_id, profile:profiles(id, full_name, email)')
                .eq('organization_id', organizationId);

            const collaboratorsList = (collaborators || []).map(c => ({
                id: (c.profile as any)?.id || c.user_id,
                full_name: (c.profile as any)?.full_name || 'Sin nombre',
                email: (c.profile as any)?.email || ''
            }));
            setAvailableCollaborators(collaboratorsList);

            // 4. Enriquecer departamentos con carga
            const enrichedDepts = (deptRes.data || []).map(d => ({
                ...d,
                workload_count: deptWorkload[d.id] || 0
            }));
            setDepartments(enrichedDepts);

            // 5. Enriquecer posiciones con empleados y carga
            const enrichedPositions = (posRes.data || []).map(p => ({
                ...p,
                workload_count: posWorkload[p.id] || 0,
                employees: (empPosRes.data || [])
                    .filter(ep => ep.position_id === p.id)
                    .map(ep => ({
                        user_id: ep.user_id,
                        user_name: (ep as any).user?.full_name || 'Sin nombre',
                        user_email: (ep as any).user?.email || '',
                        is_primary: ep.is_primary,
                        workload_count: userWorkload[ep.user_id] || 0
                    }))
            }));

            setPositions(enrichedPositions);
            setEmployeePositions(empPosRes.data || []);

            // Log for debugging (visible to developer in browser)
            console.log('Workload calculated:', {
                totalPending: workloadRes.data?.length,
                userCounts: userWorkload,
                deptCounts: deptWorkload
            });
        } catch (error: any) {
            console.error('Error loading org chart:', error.message);
        } finally {
            setLoading(false);
        }
    }

    const buildTree = (depts: Department[], parentId: string | null = null): DepartmentWithChildren[] => {
        return depts
            .filter(d => d.parent_department_id === parentId)
            .map(d => ({
                ...d,
                children: buildTree(depts, d.id),
                positions: positions
                    .filter(p => p.department_id === d.id)
                    .map(p => ({
                        ...p,
                        employees: employeePositions
                            .filter(ep => ep.position_id === p.id)
                            .map(ep => ({
                                user_id: ep.user_id,
                                user_name: (ep as any).user?.full_name || 'Sin nombre',
                                user_email: (ep as any).user?.email || '',
                                is_primary: ep.is_primary
                            }))
                    })) as any
            }));
    };

    const saveDepartment = async (dept: Partial<Department>) => {
        const { data, error } = await supabase
            .from('departments')
            .upsert({ ...dept, organization_id: organizationId })
            .select()
            .single();

        if (error) throw error;
        await loadChart();
        return data;
    };

    const deleteDepartment = async (id: string) => {
        const { error } = await supabase
            .from('departments')
            .delete()
            .eq('id', id);

        if (error) throw error;
        await loadChart();
    };

    const savePosition = async (pos: Partial<Position>) => {
        const { data, error } = await supabase
            .from('positions')
            .upsert({ ...pos, organization_id: organizationId })
            .select()
            .single();

        if (error) throw error;
        await loadChart();
        return data;
    };

    const deletePosition = async (id: string) => {
        const { error } = await supabase
            .from('positions')
            .delete()
            .eq('id', id);

        if (error) throw error;
        await loadChart();
    };

    const assignEmployee = async (userId: string, positionId: string) => {
        console.log('Asignando empleado:', { userId, positionId });
        try {
            // Verificar si ya existe la asignaci├│n para evitar duplicados
            const { data: existing } = await supabase
                .from('employee_positions')
                .select('id')
                .eq('user_id', userId)
                .eq('position_id', positionId)
                .maybeSingle();

            if (existing) {
                console.log('El empleado ya est├í asignado a este cargo.');
                return;
            }

            const { error } = await supabase
                .from('employee_positions')
                .insert({
                    user_id: userId,
                    position_id: positionId,
                    is_primary: true,
                    start_date: new Date().toISOString().split('T')[0]
                });

            if (error) {
                console.error('Error de Supabase al insertar:', error);
                throw error;
            }

            console.log('Asignaci├│n exitosa, recargando datos...');
            await loadChart();
        } catch (error: any) {
            console.error('Error en assignEmployee:', error);
            alert('Error al asignar el colaborador: ' + (error.message || 'Error desconocido'));
        }
    };

    const removeEmployee = async (userId: string, positionId: string) => {
        const { error } = await supabase
            .from('employee_positions')
            .delete()
            .eq('user_id', userId)
            .eq('position_id', positionId);

        if (error) throw error;
        await loadChart();
    };

    return {
        departments,
        positions,
        employeePositions,
        tree: buildTree(departments),
        availableCollaborators,
        loading,
        saveDepartment,
        deleteDepartment,
        savePosition,
        deletePosition,
        assignEmployee,
        removeEmployee,
        reload: loadChart
    };
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuth } from './useAuth';

export interface DepartmentHealth {
    activeTasks: number;
    overdueTasks: number;
    nearDueTasks: number;
}

export function useOrgChartAnalytics() {
    const { user } = useAuth();
    const [healthMap, setHealthMap] = useState<Record<string, DepartmentHealth>>({});
    const [loading, setLoading] = useState(true);

    const fetchAnalytics = async () => {
        try {
            const orgId = user?.organization_id;
            if (!orgId) return;

            // 1. Fetch all activities with their assigned areas
            const { data: activities } = await supabase
                .from('activities')
                .select('id, assigned_department_id, due_date_hours')
                .eq('organization_id', orgId);

            if (!activities) return;

            // 2. Fetch active process instances with all assignment details
            const { data: activeInstances } = await supabase
                .from('process_instances')
                .select('id, current_activity_id, created_at, assigned_user_id, assigned_position_id, assigned_department_id')
                .eq('organization_id', orgId)
                .eq('status', 'active');

            if (!activeInstances) {
                setHealthMap({});
                return;
            }

            // 3. Need helper data for rollups if instance only has user/position
            const { data: posRes } = await supabase.from('positions').select('id, department_id').eq('organization_id', orgId);
            const { data: empPosRes } = await supabase.from('employee_positions').select('user_id, position_id');

            const posToDept: Record<string, string> = {};
            posRes?.forEach(p => { if (p.department_id) posToDept[p.id] = p.department_id; });

            const userToDepts: Record<string, Set<string>> = {};
            empPosRes?.forEach(ep => {
                const deptId = posToDept[ep.position_id];
                if (deptId) {
                    if (!userToDepts[ep.user_id]) userToDepts[ep.user_id] = new Set();
                    userToDepts[ep.user_id].add(deptId);
                }
            });

            const newHealthMap: Record<string, DepartmentHealth> = {};

            const ensureDept = (id: string) => {
                if (!newHealthMap[id]) newHealthMap[id] = { activeTasks: 0, overdueTasks: 0, nearDueTasks: 0 };
                return newHealthMap[id];
            };

            activeInstances.forEach(instance => {
                const activity = activities.find(a => a.id === instance.current_activity_id);
                const targetDepts = new Set<string>();

                if (instance.assigned_department_id) {
                    targetDepts.add(instance.assigned_department_id);
                } else if (instance.assigned_position_id) {
                    const dId = posToDept[instance.assigned_position_id];
                    if (dId) targetDepts.add(dId);
                } else if (instance.assigned_user_id) {
                    userToDepts[instance.assigned_user_id]?.forEach(dId => targetDepts.add(dId));
                }

                targetDepts.forEach(deptId => {
                    const health = ensureDept(deptId);
                    health.activeTasks++;

                    // Calculate overdue
                    const dueHours = activity?.due_date_hours || 24;
                    const createdAt = new Date(instance.created_at);
                    const now = new Date();
                    const hoursElapsed = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60);

                    if (hoursElapsed > dueHours) {
                        health.overdueTasks++;
                    } else if ((dueHours - hoursElapsed) <= 4) {
                        health.nearDueTasks++;
                    }
                });
            });

            setHealthMap(newHealthMap);
        } catch (error) {
            console.error('Error fetching org chart analytics:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (user?.organization_id) {
            fetchAnalytics();

            // Re-fetch when instances change
            const channel = supabase.channel('org_health_changes')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'process_instances' }, fetchAnalytics)
                .subscribe();

            return () => {
                supabase.removeChannel(channel);
            };
        }
    }, [user?.organization_id]);

    return { healthMap, loading, refresh: fetchAnalytics };
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuth } from './useAuth';
import type { UserRole } from '../types';

export interface Member {
    id: string;
    full_name: string | null;
    email: string | null;
    role: UserRole;
    position?: string;
    department?: string;
}

export function useOrganizationMembers() {
    const { user, loading: authLoading } = useAuth();
    const [members, setMembers] = useState<Member[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (authLoading) return;
        if (user?.organization_id) {
            fetchMembers();
        } else {
            setLoading(false);
        }
    }, [user?.organization_id, authLoading]);

    async function fetchMembers() {
        try {
            setLoading(true);
            if (!user?.organization_id) return;

            const { data, error } = await supabase
                .from('organization_members')
                .select(`
                    user_id, 
                    role, 
                    profile:profiles(id, full_name, email),
                    employee_positions:employee_positions(
                        position:positions(title, department:departments(name))
                    )
                `)
                .eq('organization_id', user.organization_id);

            if (error) throw error;

            const mappedMembers = data.map((item: any) => {
                const empPos = item.employee_positions?.[0];
                return {
                    id: item.profile.id,
                    full_name: item.profile.full_name,
                    email: item.profile.email,
                    role: item.role,
                    position: empPos?.position?.title,
                    department: empPos?.position?.department?.name
                };
            });

            setMembers(mappedMembers);
        } catch (error) {
            console.error('Error fetching organization members:', error);
        } finally {
            setLoading(false);
        }
    }

    return { members, loading, refresh: fetchMembers };
}

