import { useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import type { Activity, Transition, WorkflowDetail } from '../types';

export function useWorkflowModeler(workflowId: string) {
    const [activities, setActivities] = useState<Activity[]>([]);
    const [transitions, setTransitions] = useState<Transition[]>([]);
    const [details, setDetails] = useState<WorkflowDetail[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        if (workflowId) {
            loadModel();
        }
    }, [workflowId]);

    async function loadModel() {
        try {
            setLoading(true);

            // Fetch activities, transitions and details first
            const [activitiesRes, transitionsRes, detailsRes] = await Promise.all([
                supabase.from('activities').select('*').eq('workflow_id', workflowId),
                supabase.from('transitions').select('*').eq('workflow_id', workflowId),
                supabase.from('workflow_details').select('*').eq('workflow_id', workflowId)
            ]);

            if (activitiesRes.error) throw activitiesRes.error;
            if (transitionsRes.error) throw transitionsRes.error;
            if (detailsRes.error) throw detailsRes.error;

            setDetails(detailsRes.data || []);

            const activityIds = (activitiesRes.data || []).map(a => a.id);

            // Fetch fields only for these activities
            let fields: any[] = [];
            if (activityIds.length > 0) {
                const { data, error } = await supabase
                    .from('activity_field_definitions')
                    .select('*')
                    .in('activity_id', activityIds);

                if (error) {
                    console.error('ÔÜá´©Å Error cargando campos (continuando sin ellos):', error.message);
                } else {
                    fields = data || [];
                }
            }

            const activitiesWithFields = (activitiesRes.data || []).map(activity => ({
                ...activity,
                // Normalize coordinates: use x_pos/y_pos if available, fallback to x/y, then 0
                x_pos: Number(activity.x_pos ?? activity.x ?? 100),
                y_pos: Number(activity.y_pos ?? activity.y ?? 100),
                fields: fields
                    .filter(f => f.activity_id === activity.id)
                    .sort((a, b) => (Number(a.order_index || 0) - Number(b.order_index || 0)))
            }));

            setActivities(activitiesWithFields);
            setTransitions(transitionsRes.data || []);
        } catch (error: any) {
            console.error('ÔØî Error fatal loading workflow model:', error.message);
        } finally {
            setLoading(false);
        }
    }

    async function saveModel(newActivities: Activity[], newTransitions: Transition[], newDetails: WorkflowDetail[] = details) {
        try {
            setSaving(true);

            // 1. Upsert Activities
            if (newActivities.length > 0) {
                const activitiesToUpsert = newActivities.map(({ fields, ...rest }) => rest);
                const { error: upsActError } = await supabase.from('activities').upsert(activitiesToUpsert);
                if (upsActError) {
                    console.error('ÔØî Error al upsertar actividades:', upsActError);
                    throw upsActError;
                }

                // 2. Upsert Field Definitions
                const allFields = newActivities.flatMap(a => (a.fields || []).map(f => {
                    const fieldToSave: any = {
                        id: f.id,
                        activity_id: a.id,
                        name: f.name,
                        label: f.label ?? f.name,
                        type: f.type,
                        required: !!f.required,
                        placeholder: f.placeholder ?? null,
                        options: f.options || [],
                        min_value: f.min_value ?? null,
                        max_value: f.max_value ?? null,
                        regex_pattern: f.regex_pattern ?? null,
                        visibility_condition: f.visibility_condition ?? null,
                    };

                    // Solo incluir order_index si f lo tiene, para evitar errores si la columna no existe
                    if (f.order_index !== undefined) {
                        fieldToSave.order_index = f.order_index;
                    }

                    return fieldToSave;
                }));

                console.log('Todos los campos a guardar (normalizados):', allFields);

                if (allFields.length > 0) {
                    // Limpiar opciones vac├¡as antes de enviar a base de datos
                    const cleanedFields = allFields.map(f => ({
                        ...f,
                        options: Array.isArray(f.options) ? f.options.filter((o: string) => o !== '') : []
                    }));

                    const { error: upsFieldsError } = await supabase.from('activity_field_definitions').upsert(cleanedFields);

                    if (upsFieldsError) {
                        // Si falla espec├¡ficamente por la columna order_index, reintentamos sin ella
                        if (upsFieldsError.message?.includes('order_index') || upsFieldsError.message?.includes('column')) {
                            console.warn('ÔÜá´©Å Reintentando guardado sin columna order_index...');
                            const fieldsWithoutOrder = cleanedFields.map(({ order_index, ...rest }) => rest);
                            const { error: retryError } = await supabase.from('activity_field_definitions').upsert(fieldsWithoutOrder);
                            if (retryError) throw retryError;
                        } else {
                            console.error('ÔØî Error al upsertar campos:', upsFieldsError);
                            throw upsFieldsError;
                        }
                    }
                }
            }

            // 3. Upsert Transitions
            if (newTransitions.length > 0) {
                const { error: upsTransError } = await supabase.from('transitions').upsert(newTransitions);
                if (upsTransError) {
                    console.error('ÔØî Error al upsertar transiciones:', upsTransError);
                    throw upsTransError;
                }
            }

            // 3.5 Upsert Details (Carpetas)
            if (newDetails.length > 0) {
                const { error: upsDetailsError } = await supabase.from('workflow_details').upsert(newDetails);
                if (upsDetailsError) {
                    console.error('ÔØî Error al upsertar detalles:', upsDetailsError);
                    throw upsDetailsError;
                }
            }

            // 4. Delete orphans
            const activityIds = newActivities.map(a => a.id);
            const transitionIds = newTransitions.map(t => t.id);
            const detailIds = newDetails.map(d => d.id);
            const fieldIds = newActivities.flatMap(a => (a.fields || []).map(f => f.id));


            // Delete orphaned transitions
            if (transitionIds.length > 0) {
                const { error: delTransError } = await supabase.from('transitions')
                    .delete()
                    .eq('workflow_id', workflowId)
                    .not('id', 'in', transitionIds);
                if (delTransError) console.warn('ÔÜá´©Å No se pudieron borrar algunas transiciones:', delTransError);
            } else {
                await supabase.from('transitions').delete().eq('workflow_id', workflowId);
            }

            // Delete orphaned field definitions
            if (activityIds.length > 0) {
                if (fieldIds.length > 0) {
                    const { error: delFieldsError } = await supabase.from('activity_field_definitions')
                        .delete()
                        .in('activity_id', activityIds)
                        .not('id', 'in', fieldIds);
                    if (delFieldsError) console.error('ÔØî Error al borrar campos hu├®rfanos:', delFieldsError);
                } else {
                    await supabase.from('activity_field_definitions')
                        .delete()
                        .in('activity_id', activityIds);
                }
            }

            // Delete orphaned activities
            if (activityIds.length > 0) {
                const { error: delActError } = await supabase.from('activities')
                    .delete()
                    .eq('workflow_id', workflowId)
                    .not('id', 'in', activityIds);
                if (delActError) {
                    console.warn('ÔÜá´©Å No se pudieron borrar algunas actividades (posiblemente en uso):', delActError.message);
                }
            } else {
                await supabase.from('activities').delete().eq('workflow_id', workflowId);
            }

            // Delete orphaned details
            if (detailIds.length > 0) {
                const { error: delDetailsError } = await supabase.from('workflow_details')
                    .delete()
                    .eq('workflow_id', workflowId)
                    .not('id', 'in', detailIds);
                if (delDetailsError) console.warn('ÔÜá´©Å No se pudieron borrar detalles:', delDetailsError);
            } else {
                await supabase.from('workflow_details').delete().eq('workflow_id', workflowId);
            }

            setActivities(newActivities);
            setTransitions(newTransitions);
            setDetails(newDetails);

            return { success: true };
        } catch (error: any) {
            console.error('­ƒöÑ Error Cr├¡tico en saveModel:', error.message);
            return { success: false, error: error.message };
        } finally {
            setSaving(false);
        }
    }

    return {
        activities,
        setActivities,
        transitions,
        setTransitions,
        details,
        setDetails,
        loading,
        saving,
        saveModel,
        reload: loadModel
    };
}

import { useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import type { Workflow } from '../types';

export function useWorkflows() {
    const [workflows, setWorkflows] = useState<Workflow[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        fetchWorkflows();

        // Set up real-time subscription
        const subscription = supabase
            .channel('workflows-channel')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'workflows' }, () => {
                fetchWorkflows();
            })
            .subscribe();

        return () => {
            supabase.removeChannel(subscription);
        };
    }, []);

    async function fetchWorkflows() {
        try {
            setLoading(true);
            const { data, error } = await supabase
                .from('workflows')
                .select('*')
                .order('created_at', { ascending: false });

            if (error) throw error;
            setWorkflows(data || []);
        } catch (err: any) {
            console.error('Error fetching workflows:', err.message);
            setError(err.message);
        } finally {
            setLoading(false);
        }
    }

    async function createWorkflow(workflow: Partial<Workflow>) {
        try {
            const { data, error } = await supabase
                .from('workflows')
                .insert([workflow])
                .select();

            if (error) throw error;
            if (data && data.length > 0) {
                setWorkflows(prev => [data[0], ...prev]);
            }
            return { data, error: null };
        } catch (err: any) {
            console.error('Error creating workflow:', err);
            return { data: null, error: err.message || 'Error desconocido al crear flujo' };
        }
    }

    async function updateWorkflow(id: string, updates: Partial<Workflow>) {
        try {
            const { data, error } = await supabase
                .from('workflows')
                .update(updates)
                .eq('id', id)
                .select();

            if (error) throw error;
            if (data && data.length > 0) {
                setWorkflows(prev => prev.map(w => w.id === id ? data[0] : w));
            }
            return { data, error: null };
        } catch (err: any) {
            console.error('Error updating workflow:', err);
            return { data: null, error: err.message || 'Error desconocido al actualizar flujo' };
        }
    }

    async function deleteWorkflow(id: string) {
        try {
            const { error } = await supabase
                .from('workflows')
                .delete()
                .eq('id', id);

            if (error) throw error;
            setWorkflows(prev => prev.filter(w => w.id !== id));
            return { error: null };
        } catch (err: any) {
            console.error('Error deleting workflow:', err.message);
            return { error: err.message };
        }
    }

    async function duplicateWorkflow(id: string) {
        try {
            setLoading(true);
            // 1. Get original workflow
            const { data: workflow, error: wfError } = await supabase
                .from('workflows')
                .select('*')
                .eq('id', id)
                .single();
            if (wfError) throw wfError;

            // 2. Get activities
            const { data: activities, error: actError } = await supabase
                .from('activities')
                .select('*')
                .eq('workflow_id', id);
            if (actError) throw actError;

            // 3. Get all field definitions for these activities
            const activityIds = (activities || []).map(a => a.id);
            let fields: any[] = [];
            if (activityIds.length > 0) {
                const { data, error } = await supabase
                    .from('activity_field_definitions')
                    .select('*')
                    .in('activity_id', activityIds);
                if (error) throw error;
                fields = data || [];
            }

            // 4. Get transitions
            const { data: transitions, error: transError } = await supabase
                .from('transitions')
                .select('*')
                .eq('workflow_id', id);
            if (transError) throw transError;

            // 5. Create new workflow
            // Note: version might be e.g. "v1.2", parse the numeric part
            const currentVersionStr = (workflow.version || 'v1.0').replace('v', '');
            const nextVersionNum = (parseFloat(currentVersionStr) + 0.1).toFixed(1);
            const nextVersion = `v${nextVersionNum}`;

            const newWfData: any = {
                organization_id: workflow.organization_id,
                name: `${workflow.name} (${nextVersion})`,
                description: workflow.description,
                created_by: workflow.created_by,
                status: 'draft',
                version: nextVersion,
                parent_id: workflow.parent_id || workflow.id,
                name_template: workflow.name_template
            };

            let { data: newWf, error: newWfError } = await supabase
                .from('workflows')
                .insert([newWfData])
                .select()
                .single();

            // Fallback if version/parent_id columns don't exist
            if (newWfError && (newWfError.message?.includes('version') || newWfError.message?.includes('parent_id') || newWfError.code === '42703')) {
                console.warn('Versioning columns missing, retrying without them...');
                delete newWfData.version;
                delete newWfData.parent_id;
                const retry = await supabase
                    .from('workflows')
                    .insert([newWfData])
                    .select()
                    .single();
                newWf = retry.data;
                newWfError = retry.error;
            }

            if (newWfError) throw newWfError;
            if (!newWf) throw new Error('Failed to create new workflow copy');

            // 6. Map old activity IDs to new IDs
            const activityIdMap: Record<string, string> = {};
            for (const activity of (activities || [])) {
                // Remove id and metadata fields before insert
                const { id: _, created_at: __, workflow_id: ___, ...activityData } = activity;
                const { data: newAct, error: newActError } = await supabase
                    .from('activities')
                    .insert([{
                        ...activityData,
                        workflow_id: newWf.id
                    }])
                    .select()
                    .single();

                if (newActError) throw newActError;
                activityIdMap[activity.id] = newAct.id;

                // 7. Clone fields for this activity
                const activityFields = fields.filter(f => f.activity_id === activity.id);
                if (activityFields.length > 0) {
                    const fieldsToInsert = activityFields.map(f => {
                        const { id: _, activity_id: __, ...fData } = f;
                        return {
                            ...fData,
                            activity_id: newAct.id
                        };
                    });
                    const { error: fError } = await supabase
                        .from('activity_field_definitions')
                        .insert(fieldsToInsert);
                    if (fError) throw fError;
                }
            }

            // 8. Clone transitions
            if ((transitions || []).length > 0) {
                const transitionsToInsert = transitions.map(t => {
                    const { id: _, workflow_id: __, ...tData } = t;
                    return {
                        ...tData,
                        workflow_id: newWf.id,
                        source_id: activityIdMap[t.source_id],
                        target_id: activityIdMap[t.target_id]
                    };
                });
                const { error: tError } = await supabase
                    .from('transitions')
                    .insert(transitionsToInsert);
                if (tError) throw tError;
            }

            await fetchWorkflows();
            return { data: newWf, error: null };
        } catch (err: any) {
            console.error('Error duplicating workflow:', err);
            return { data: null, error: err.message || 'Error al duplicar flujo' };
        } finally {
            setLoading(false);
        }
    }

    return {
        workflows,
        loading,
        error,
        createWorkflow,
        updateWorkflow,
        deleteWorkflow,
        duplicateWorkflow,
        refresh: fetchWorkflows
    };
}

import type { Activity, Transition } from '../types';

export type AIProviderName = 'openai' | 'gemini';

export interface AIGeneratedWorkflow {
    activities: Activity[];
    transitions: Transition[];
}

export async function generateWorkflowWithAI(prompt: string, apiKey: string, provider: AIProviderName = 'openai'): Promise<AIGeneratedWorkflow> {
    const systemPrompt = `
Eres un Analista Avanzado de Negocios y Arquitecto de Procesos BPMN. Tu misi├│n es generar incre├¡bles flujos de trabajo funcionales para "BPM Manager". 
El usuario te dar├í una idea en lenguaje natural de un proceso, y t├║ devolver├ís ├ÜNICAMENTE un JSON v├ílido con la estructura exacta detallada abajo. ┬íNADA de backticks \`\`\`, SOLO el raw JSON!

### Estructura del JSON Esperado:
Un objeto con dos arreglos: \`activities\` y \`transitions\`. Debes usar IDs num├®ricos simples como "1", "2", "3" para que puedas relacionarlos f├ícilmente. El sistema los convertir├í a UUIDs luego.

\`\`\`json
{
  "activities": [
    {
      "id": "1",
      "workflow_id": "temp-workflow-id",
      "name": "Inicio Solicitud",
      "type": "start",
      "x_pos": 100,
      "y_pos": 200,
      "fields": [
        { "id": "f1", "activity_id": "1", "name": "motivo", "label": "Motivo", "type": "textarea", "required": true, "order_index": 0 }
      ]
    },
    {
      "id": "2",
      "workflow_id": "temp-workflow-id",
      "name": "Revisar Formulario",
      "type": "decision",
      "x_pos": 450,
      "y_pos": 200
    }
  ],
  "transitions": [
    {
      "id": "t1",
      "workflow_id": "temp-workflow-id",
      "source_id": "1",
      "target_id": "2",
      "condition": "Aprobado"
    }
  ]
}
\`\`\`

### Criterios y Reglas ORO (MANDATORIAS):
1. **El Primer Nodo (\`activities\`)**: Siempre debe ser \`type: 'start'\` y llamarse algo "Inicio". Debe contener TODOS los \`fields\` iniciales (tipos v├ílidos: 'text', 'number', 'date', 'boolean', 'select', 'textarea', 'currency', 'email').
2. **Nodos de Decisi├│n y Ramas**: Usa un \`decision\` para dividir el flujo. Importante: Para las \`transitions\`, si salen de una \`decision\`, usa el campo \`condition\` para poner la ruta (ej. "Aprobado" va a un lado, "Rechazado" va a otro lado).
3. **Flujo Visual**: 
   - Start Node: \`x_pos: 100\`
   - Tarea Sig: \`x_pos: 450\`
   - Decisi├│n/Siguiente: \`x_pos: 800\`
   - Final: \`x_pos: 1150\`
   Avanza gradualmente en X (\`+350\`). Si hay ramas paralelas o de rechazo, s├║belas o b├íjalas en Y (ej. \`y_pos: 400\` o \`0\`).
4. **Nodos de Finalizaci├│n**: Termina las ramas con al menos un nodo \`type: 'end'\`.
5. ESTRICTO FORMATO DE RESPUESTA: S├│lo el JSON CRUSO. Debe comenzar por '{' y terminar en '}'. SIN palabras de saludo ni comillas invertidas.
`;

    let rawContent = "{}";

    if (provider === 'gemini') {
        try {
            const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`;
            const response = await fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    system_instruction: {
                        parts: [{ text: systemPrompt }]
                    },
                    contents: [
                        { role: 'user', parts: [{ text: prompt }] }
                    ],
                    generationConfig: {
                        temperature: 0.2,
                        responseMimeType: "application/json"
                    }
                })
            });

            if (!response.ok) {
                const errorData = await response.json();
                throw new Error(errorData.error?.message || 'Error de comunicaci├│n con Gemini');
            }

            const data = await response.json();
            rawContent = data.candidates?.[0]?.content?.parts?.[0]?.text || "{}";

        } catch (error: any) {
            console.error("Gemini Error:", error);
            throw new Error(`Error de comunicaci├│n con Gemini: ${error.message || 'Error desconocido'}`);
        }
    } else {
        const response = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`,
            },
            body: JSON.stringify({
                model: 'gpt-4o-mini', // Usando gpt-4o-mini por defecto para buena relaci├│n costo/calidad
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: prompt }
                ],
                temperature: 0.2, // Baja temperatura para JSON estables
            })
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(errorData.error?.message || 'Error de comunicaci├│n con OpenAI');
        }

        const data = await response.json();
        rawContent = data.choices[0]?.message?.content || '{}';
    }

    try {
        // Mejoramos la robustez buscando el corchete de objeto para limpiar
        let cleanedContent = rawContent;
        const startIndex = rawContent.indexOf('{');
        const endIndex = rawContent.lastIndexOf('}');

        if (startIndex !== -1 && endIndex !== -1 && endIndex > startIndex) {
            cleanedContent = rawContent.substring(startIndex, endIndex + 1);
        }

        const generatedData = JSON.parse(cleanedContent) as { activities?: any[], transitions?: any[] };

        const activities = generatedData.activities || [];
        const transitions = generatedData.transitions || [];

        // Mapeo seguro de IDs temporales a UUIDs reales
        const idMap = new Map<string, string>();

        const finalActivities: Activity[] = activities.map(act => {
            const newId = crypto.randomUUID();
            idMap.set(String(act.id), newId);

            // Fix field ids as well silently
            const finalFields = (act.fields || []).map((f: any) => ({
                ...f,
                id: crypto.randomUUID(),
                activity_id: newId
            }));

            return {
                ...act,
                id: newId,
                workflow_id: 'temp', // We replace this upstream
                fields: finalFields
            };
        });

        const finalTransitions: Transition[] = transitions.map(tr => {
            return {
                ...tr,
                id: crypto.randomUUID(),
                workflow_id: 'temp',
                source_id: idMap.get(String(tr.source_id)) || tr.source_id,
                target_id: idMap.get(String(tr.target_id)) || tr.target_id
            };
        });

        return { activities: finalActivities, transitions: finalTransitions };

    } catch (e) {
        throw new Error("La IA no devolvi├│ un JSON v├ílido. Intenta cambiar tu prompt.");
    }
}

